window.LIBRARY = {"chumash":{"id":"chumash","kind":"tanach","title":"חֻמָּשׁ בְּרֵאשִׁית","sub":"פְּרָקִים א׳–ג׳ · עִם פֵּרוּשׁ רָשִׁ״י","icon":"📕","perakim":[{"n":"א","units":[{"ref":"בְּרֵאשִׁית א׳, א׳","pasuk":"בְּרֵאשִׁ֖ית בָּרָ֣א אֱלֹהִ֑ים אֵ֥ת הַשָּׁמַ֖יִם וְאֵ֥ת הָאָֽרֶץ׃","rashi":[{"d":"ברא אלהים","t":"ולא נאמר ברא ה', שבתחלה עלה במחשבה לבראתו במדת הדין, ראה שאין העולם מתקים, הקדים מדת רחמים ושתפה למה\"ד, והיינו דכתיב ביום עשות ה' אלהים ארץ ושמים:"}]},{"ref":"בְּרֵאשִׁית א׳, ב׳","pasuk":"וְהָאָ֗רֶץ הָיְתָ֥ה תֹ֙הוּ֙ וָבֹ֔הוּ וְחֹ֖שֶׁךְ עַל־פְּנֵ֣י תְה֑וֹם וְר֣וּחַ אֱלֹהִ֔ים מְרַחֶ֖פֶת עַל־פְּנֵ֥י הַמָּֽיִם׃","rashi":[{"d":"תהו ובהו","t":"תהו לשון תמה ושממון, שאדם תוהא ומשתומם על בהו שבה:"},{"d":"תהו","t":"אשטורדי\"שון בלע\"ז:"},{"d":"בהו","t":"לשון רקות וצדו:"}]},{"ref":"בְּרֵאשִׁית א׳, ג׳","pasuk":"וַיֹּ֥אמֶר אֱלֹהִ֖ים יְהִ֣י א֑וֹר וַֽיְהִי־אֽוֹר׃","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, ד׳","pasuk":"וַיַּ֧רְא אֱלֹהִ֛ים אֶת־הָא֖וֹר כִּי־ט֑וֹב וַיַּבְדֵּ֣ל אֱלֹהִ֔ים בֵּ֥ין הָא֖וֹר וּבֵ֥ין הַחֹֽשֶׁךְ׃","rashi":[{"d":"וירא אלהים את האור כי טוב ויבדל","t":"אף בזה אנו צריכין לדברי אגדה, ראהו שאינו כדאי להשתמש בו רשעים, והבדילו לצדיקים לעתיד לבא. ולפי פשוטו כך פרשהו, ראהו כי טוב, ואין נאה לו ולחשך שיהיו משתמשים בערבוביא, וקבע לזה תחומו ביום, ולזה תחומו בלילה:"}]},{"ref":"בְּרֵאשִׁית א׳, ה׳","pasuk":"וַיִּקְרָ֨א אֱלֹהִ֤ים&thinsp;׀&thinsp;לָאוֹר֙ י֔וֹם וְלַחֹ֖שֶׁךְ קָ֣רָא לָ֑יְלָה וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם אֶחָֽד׃&nbsp;{פ}","rashi":[{"d":"יום אחד","t":"לפי סדר לשון הפרשה היה לו לכתב יום ראשון, כמו שכתוב בשאר הימים שני, שלישי, רביעי, למה כתב אחד? לפי שהיה הקב\"ה יחיד בעולמו, שלא נבראו המלאכים עד יום שני, כך מפרש בב\"ר:"}]},{"ref":"בְּרֵאשִׁית א׳, ו׳","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֔ים יְהִ֥י רָקִ֖יעַ בְּת֣וֹךְ הַמָּ֑יִם וִיהִ֣י מַבְדִּ֔יל בֵּ֥ין מַ֖יִם לָמָֽיִם׃","rashi":[{"d":"יהי רקיע","t":"יחזק הרקיע, שאף על פי שנבראו שמים ביום א' עדין לחים היו וקרשו בשני מגערת הקב\"ה באמרו יהי רקיע, וזהו שכתב (איוב כ\"ו) עמודי שמים ירופפו – כל יום ראשון, ובשני יתמהו מגערתו, כאדם שמשתומם ועומד מגערת המאים עליו:"},{"d":"בתוך המים","t":"באמצע המים, שיש הפרש בין מים העליונים לרקיע כמו בין הרקיע למים שעל הארץ, הא למדת, שהם תלויים במאמרו של מלך:"}]},{"ref":"בְּרֵאשִׁית א׳, ז׳","pasuk":"וַיַּ֣עַשׂ אֱלֹהִים֮ אֶת־הָרָקִ֒יעַ֒ וַיַּבְדֵּ֗ל בֵּ֤ין הַמַּ֙יִם֙ אֲשֶׁר֙ מִתַּ֣חַת לָרָקִ֔יעַ וּבֵ֣ין הַמַּ֔יִם אֲשֶׁ֖ר מֵעַ֣ל לָרָקִ֑יעַ וַֽיְהִי־כֵֽן׃","rashi":[{"d":"ויעש אלהים את הרקיע","t":"תקנו על עמדו, והיא עשיתו, כמו ועשתה את צפרניה (דברים כ\"א):"}]},{"ref":"בְּרֵאשִׁית א׳, ח׳","pasuk":"וַיִּקְרָ֧א אֱלֹהִ֛ים לָֽרָקִ֖יעַ שָׁמָ֑יִם וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם שֵׁנִֽי׃&nbsp;{פ}","rashi":[{"d":"ויקרא אלהים לרקיע שמים","t":"שא מים, שם מים, אש ומים, שערבן זה בזה ועשה מהם שמים:"}]},{"ref":"בְּרֵאשִׁית א׳, ט׳","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֗ים יִקָּו֨וּ הַמַּ֜יִם מִתַּ֤חַת הַשָּׁמַ֙יִם֙ אֶל־מָק֣וֹם אֶחָ֔ד וְתֵרָאֶ֖ה הַיַּבָּשָׁ֑ה וַֽיְהִי־כֵֽן׃","rashi":[{"d":"יקוו המים","t":"שהיו שטוחין על פני כל הארץ והקום באוקינוס הוא הים הגדול שבכל הימים:"}]},{"ref":"בְּרֵאשִׁית א׳, י׳","pasuk":"וַיִּקְרָ֨א אֱלֹהִ֤ים&thinsp;׀&thinsp;לַיַּבָּשָׁה֙ אֶ֔רֶץ וּלְמִקְוֵ֥ה הַמַּ֖יִם קָרָ֣א יַמִּ֑ים וַיַּ֥רְא אֱלֹהִ֖ים כִּי־טֽוֹב׃","rashi":[{"d":"קרא ימים","t":"והלא ים אחד הוא? אלא אינו דומה טעם דג העולה מן הים בעכו לטעם דג העולה מן הים באספמיא:"}]},{"ref":"בְּרֵאשִׁית א׳, י״א","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֗ים תַּֽדְשֵׁ֤א הָאָ֙רֶץ֙ דֶּ֗שֶׁא עֵ֚שֶׂב מַזְרִ֣יעַ זֶ֔רַע עֵ֣ץ פְּרִ֞י עֹ֤שֶׂה פְּרִי֙ לְמִינ֔וֹ אֲשֶׁ֥ר זַרְעוֹ־ב֖וֹ עַל־הָאָ֑רֶץ וַֽיְהִי־כֵֽן׃","rashi":[{"d":"תדשא הארץ דשא עשב","t":"לא דשא לשון עשב ולא עשב לשון דשא, ולא היה לשון המקרא לומר תעשיב הארץ, שמיני דשאים מחלקין, כל אחד לעצמו נקרא עשב פלוני, ואין לשון למדבר לומר דשא פלוני, שלשון דשא הוא לבישת הארץ כשהיא מתמלאת בדשאים:"},{"d":"תדשא הארץ","t":"תתמלא ותתכסה לבוש עשבים. בלשון לעז נקרא דשא ארבריץ, כלן בערבוביא, וכל שרש לעצמו נקרא עשב:"},{"d":"מזריע זרע","t":"שיגדל בו זרעו לזרע ממנו במקום אחר:"}]},{"ref":"בְּרֵאשִׁית א׳, י״ב","pasuk":"וַתּוֹצֵ֨א הָאָ֜רֶץ דֶּ֠שֶׁא עֵ֣שֶׂב מַזְרִ֤יעַ זֶ֙רַע֙ לְמִינֵ֔הוּ וְעֵ֧ץ עֹֽשֶׂה־פְּרִ֛י אֲשֶׁ֥ר זַרְעוֹ־ב֖וֹ לְמִינֵ֑הוּ וַיַּ֥רְא אֱלֹהִ֖ים כִּי־טֽוֹב׃","rashi":[{"d":"ותוצא הארץ וגו'","t":"אע\"פ שלא נאמר למינהו בדשאין בצווייהן, שמעו שנצטוו האילנות על כך, נשאו ק\"ו בעצמן, כמפרש באגדה בשחיטת חלין:"}]},{"ref":"בְּרֵאשִׁית א׳, י״ג","pasuk":"וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם שְׁלִישִֽׁי׃&nbsp;{פ}","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, י״ד","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֗ים יְהִ֤י מְאֹרֹת֙ בִּרְקִ֣יעַ הַשָּׁמַ֔יִם לְהַבְדִּ֕יל בֵּ֥ין הַיּ֖וֹם וּבֵ֣ין הַלָּ֑יְלָה וְהָי֤וּ לְאֹתֹת֙ וּלְמ֣וֹעֲדִ֔ים וּלְיָמִ֖ים וְשָׁנִֽים׃","rashi":[{"d":"יהי מארת וגו'","t":"מיום ראשון נבראו וברביעי צוה עליהם להתלות ברקיע, וכן כל תולדות שמים וארץ נבראו מיום ראשון, וכל אחד ואחד נקבע ביום שנגזר עליו, הוא שכתוב את השמים, לרבות תולדותיהם, ואת הארץ, לרבות תולדותיה:"},{"d":"יהי מארת","t":"חסר וי\"ו כתיב, על שהוא יום מארה לפל אסכרה בתינוקות, הוא ששנינו בד' היו מתענים על אסכרה שלא תפל בתינוקות:"},{"d":"להבדיל בין היום ובין הלילה","t":"משנגנז האור הראשון, אבל בשבעת ימי בראשית שמשו האור והחשך הראשונים יחד בין ביום ובין בלילה:"}]},{"ref":"בְּרֵאשִׁית א׳, ט״ו","pasuk":"וְהָי֤וּ לִמְאוֹרֹת֙ בִּרְקִ֣יעַ הַשָּׁמַ֔יִם לְהָאִ֖יר עַל־הָאָ֑רֶץ וַֽיְהִי־כֵֽן׃","rashi":[{"d":"והיו למאורת","t":"עוד זאת ישמשו, שיאירו לעולם:"}]},{"ref":"בְּרֵאשִׁית א׳, ט״ז","pasuk":"וַיַּ֣עַשׂ אֱלֹהִ֔ים אֶת־שְׁנֵ֥י הַמְּאֹרֹ֖ת הַגְּדֹלִ֑ים אֶת־הַמָּא֤וֹר הַגָּדֹל֙ לְמֶמְשֶׁ֣לֶת הַיּ֔וֹם וְאֶת־הַמָּא֤וֹר הַקָּטֹן֙ לְמֶמְשֶׁ֣לֶת הַלַּ֔יְלָה וְאֵ֖ת הַכּוֹכָבִֽים׃","rashi":[{"d":"המארת הגדולים","t":"שוים נבראו ונתמעטה הלבנה על שקטרגה ואמרה א\"א לשני מלכים שישתמשו בכתר אחד:"},{"d":"ואת הכוכבים","t":"על ידי שמעט את הלבנה הרבה צבאיה להפיס דעתה:"}]},{"ref":"בְּרֵאשִׁית א׳, י״ז","pasuk":"וַיִּתֵּ֥ן אֹתָ֛ם אֱלֹהִ֖ים בִּרְקִ֣יעַ הַשָּׁמָ֑יִם לְהָאִ֖יר עַל־הָאָֽרֶץ׃","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, י״ח","pasuk":"וְלִמְשֹׁל֙ בַּיּ֣וֹם וּבַלַּ֔יְלָה וּֽלְהַבְדִּ֔יל בֵּ֥ין הָא֖וֹר וּבֵ֣ין הַחֹ֑שֶׁךְ וַיַּ֥רְא אֱלֹהִ֖ים כִּי־טֽוֹב׃","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, י״ט","pasuk":"וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם רְבִיעִֽי׃&nbsp;{פ}","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, כ׳","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֔ים יִשְׁרְצ֣וּ הַמַּ֔יִם שֶׁ֖רֶץ נֶ֣פֶשׁ חַיָּ֑ה וְעוֹף֙ יְעוֹפֵ֣ף עַל־הָאָ֔רֶץ עַל־פְּנֵ֖י רְקִ֥יעַ הַשָּׁמָֽיִם׃","rashi":[{"d":"נפש חיה","t":"שיהא בה חיות:"},{"d":"שרץ","t":"כל דבר חי שאינו גבוה מן הארץ קרוי שרץ: בעוף, כגון זבובים, בשקצים, כגון נמלים וחפושים ותולעים, בבריות, כגון חלד ועכבר וחמט וכיוצא בהם, וכל הדגים:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״א","pasuk":"וַיִּבְרָ֣א אֱלֹהִ֔ים אֶת־הַתַּנִּינִ֖ם הַגְּדֹלִ֑ים וְאֵ֣ת כׇּל־נֶ֣פֶשׁ הַֽחַיָּ֣ה&thinsp;׀&thinsp;הָֽרֹמֶ֡שֶׂת אֲשֶׁר֩ שָׁרְצ֨וּ הַמַּ֜יִם לְמִֽינֵהֶ֗ם וְאֵ֨ת כׇּל־ע֤וֹף כָּנָף֙ לְמִינֵ֔הוּ וַיַּ֥רְא אֱלֹהִ֖ים כִּי־טֽוֹב׃","rashi":[{"d":"התנינם","t":"דגים גדולים שבים, ובדברי אגדה הוא לויתן ובן זוגו שבראם זכר ונקבה והרג את הנקבה ומלחה לצדיקים לעתיד לבא, שאם יפרו וירבו לא יתקים העולם בפניהם:"},{"d":"נפש החיה","t":"שיש בה חיות:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ב","pasuk":"וַיְבָ֧רֶךְ אֹתָ֛ם אֱלֹהִ֖ים לֵאמֹ֑ר פְּר֣וּ וּרְב֗וּ וּמִלְא֤וּ אֶת־הַמַּ֙יִם֙ בַּיַּמִּ֔ים וְהָע֖וֹף יִ֥רֶב בָּאָֽרֶץ׃","rashi":[{"d":"ויברך אותם","t":"לפי שמחסרים אותם וצדין מהם ואוכלין אותם, הצרכו לברכה, ואף החיות הצרכו לברכה, אלא מפני הנחש שעתיד לקללה, לכך לא ברכן, שלא יהא הוא בכלל:"},{"d":"פרו","t":"ל' פרי כלו' עשו פרות:"},{"d":"ורבו","t":"אם לא אמר אלא פרו, היה אחד מוליד אחד ולא יותר, ובא ורבו שאחד מוליד הרבה:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ג","pasuk":"וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם חֲמִישִֽׁי׃&nbsp;{פ}","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, כ״ד","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֗ים תּוֹצֵ֨א הָאָ֜רֶץ נֶ֤פֶשׁ חַיָּה֙ לְמִינָ֔הּ בְּהֵמָ֥ה וָרֶ֛מֶשׂ וְחַֽיְתוֹ־אֶ֖רֶץ לְמִינָ֑הּ וַֽיְהִי־כֵֽן׃","rashi":[{"d":"תוצא הארץ","t":"הוא שפרשתי שהכל נברא מיום ראשון, ולא הצרכו אלא להוציאם:"},{"d":"נפש חיה","t":"שיש בה חיות:"},{"d":"ורמש","t":"הם שרצים, שהם נמוכים ורומשים על הארץ ונראים כאלו נגררים שאין הלוכן נכר. כל לשון רמש ושרץ בלשוננו קונמו\"בריש בלע\"ז:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ה","pasuk":"וַיַּ֣עַשׂ אֱלֹהִים֩ אֶת־חַיַּ֨ת הָאָ֜רֶץ לְמִינָ֗הּ וְאֶת־הַבְּהֵמָה֙ לְמִינָ֔הּ וְאֵ֛ת כׇּל־רֶ֥מֶשׂ הָֽאֲדָמָ֖ה לְמִינֵ֑הוּ וַיַּ֥רְא אֱלֹהִ֖ים כִּי־טֽוֹב׃","rashi":[{"d":"ויעש","t":"תקנם בצביונם ובקומתן:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ו","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֔ים נַֽעֲשֶׂ֥ה אָדָ֛ם בְּצַלְמֵ֖נוּ כִּדְמוּתֵ֑נוּ וְיִרְדּוּ֩ בִדְגַ֨ת הַיָּ֜ם וּבְע֣וֹף הַשָּׁמַ֗יִם וּבַבְּהֵמָה֙ וּבְכׇל־הָאָ֔רֶץ וּבְכׇל־הָרֶ֖מֶשׂ הָֽרֹמֵ֥שׂ עַל־הָאָֽרֶץ׃","rashi":[{"d":"נעשה אדם","t":"אע\"פ שלא סיעוהו ביצירתו ויש מקום למינים לרדות, לא נמנע הכתוב מללמד דרך ארץ ומדת ענוה שיהא הגדול נמלך ונוטל רשות מן הקטן; ואם כתב אעשה אדם, לא למדנו שיהא מדבר עם בית דינו, אלא עם עצמו, ותשובת המינים כתב בצדו, ויברא את האדם, ולא כתב ויבראו:"},{"d":"בצלמנו","t":"בדפוס שלנו:"},{"d":"כדמותנו","t":"להבין ולהשכיל:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ז","pasuk":"וַיִּבְרָ֨א אֱלֹהִ֤ים&thinsp;׀&thinsp;אֶת־הָֽאָדָם֙ בְּצַלְמ֔וֹ בְּצֶ֥לֶם אֱלֹהִ֖ים בָּרָ֣א אֹת֑וֹ זָכָ֥ר וּנְקֵבָ֖ה בָּרָ֥א אֹתָֽם׃","rashi":[{"d":"ויברא אלהים את האדם בצלמו","t":"בדפוס העשוי לו, שהכל נברא במאמר והוא נברא בידים, שנאמר ותשת עלי כפכה (תהילים קל\"ט); נעשה בחותם כמטבע העשויה על ידי רשם שקורין קוי\"ן בלע\"ז וכן הוא אומר תתהפך כחמר חותם (איוב ל\"ח):"},{"d":"בצלם אלהים ברא אותו","t":"פרש לך שאותו צלם המתקן לו, צלם דיוקן יוצרו הוא:"},{"d":"זכר ונקבה ברא אותם","t":"ולהלן הוא אומר ויקח אחת מצלעתיו וגו' (בראשית ב')? מדרש אגדה שבראו שני פרצופים בבריאה ראשונה, ואחר כך חלקו. ופשוטו של מקרא, כאן הודיעך שנבראו שניהם בששי ולא פי' לך כיצד בריתן, ופרש לך במקום אחר:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ח","pasuk":"וַיְבָ֣רֶךְ אֹתָם֮ אֱלֹהִים֒ וַיֹּ֨אמֶר לָהֶ֜ם אֱלֹהִ֗ים פְּר֥וּ וּרְב֛וּ וּמִלְא֥וּ אֶת־הָאָ֖רֶץ וְכִבְשֻׁ֑הָ וּרְד֞וּ בִּדְגַ֤ת הַיָּם֙ וּבְע֣וֹף הַשָּׁמַ֔יִם וּבְכׇל־חַיָּ֖ה הָֽרֹמֶ֥שֶׂת עַל־הָאָֽרֶץ׃","rashi":[{"d":"וכבשה","t":"חסר וי\"ו ללמדך שהזכר כובש את הנקבה, שלא תהא יצאנית, ועוד ללמדך שהאיש שדרכו לכבש מצוה על פריה ורביה ולא האשה:"}]},{"ref":"בְּרֵאשִׁית א׳, כ״ט","pasuk":"וַיֹּ֣אמֶר אֱלֹהִ֗ים הִנֵּה֩ נָתַ֨תִּי לָכֶ֜ם אֶת־כׇּל־עֵ֣שֶׂב&thinsp;׀ זֹרֵ֣עַ זֶ֗רַע אֲשֶׁר֙ עַל־פְּנֵ֣י כׇל־הָאָ֔רֶץ וְאֶת־כׇּל־הָעֵ֛ץ אֲשֶׁר־בּ֥וֹ פְרִי־עֵ֖ץ זֹרֵ֣עַ זָ֑רַע לָכֶ֥ם יִֽהְיֶ֖ה לְאׇכְלָֽה׃","rashi":[{"d":"לכם יהיה לאכלה ולכל חית הארץ","t":"השוה להם בהמות וחיות למאכל, ולא הרשה לאדם ולאשתו להמית בריה ולאכל בשר, אך כל ירק עשב יאכלו יחד כלם, וכשבאו בני נח התיר להם בשר, שנאמר כל רמש אשר הוא חי וגו' כירק עשב שהתרתי לאדם הראשון נתתי לכם את כל:"}]},{"ref":"בְּרֵאשִׁית א׳, ל׳","pasuk":"וּֽלְכׇל־חַיַּ֣ת הָ֠אָ֠רֶץ וּלְכׇל־ע֨וֹף הַשָּׁמַ֜יִם וּלְכֹ֣ל&thinsp;׀ רוֹמֵ֣שׂ עַל־הָאָ֗רֶץ אֲשֶׁר־בּוֹ֙ נֶ֣פֶשׁ חַיָּ֔ה אֶת־כׇּל־יֶ֥רֶק עֵ֖שֶׂב לְאׇכְלָ֑ה וַֽיְהִי־כֵֽן׃","rashi":[]},{"ref":"בְּרֵאשִׁית א׳, ל״א","pasuk":"וַיַּ֤רְא אֱלֹהִים֙ אֶת־כׇּל־אֲשֶׁ֣ר עָשָׂ֔ה וְהִנֵּה־ט֖וֹב מְאֹ֑ד וַֽיְהִי־עֶ֥רֶב וַֽיְהִי־בֹ֖קֶר י֥וֹם הַשִּׁשִּֽׁי׃&nbsp;{פ}","rashi":[{"d":"יום הששי","t":"הוסיף ה' בששי בגמר מעשה בראשית, לומר שהתנה עמהם, על מנת שיקבלו עליהם ישראל חמשה חמשי תורה. דבר אחר יום הששי, כלם תלוים ועומדים עד יום הששי, הוא ו' בסיון המוכן למתן תורה:"}]}]},{"n":"ב","units":[{"ref":"בְּרֵאשִׁית ב׳, א׳","pasuk":"וַיְכֻלּ֛וּ הַשָּׁמַ֥יִם וְהָאָ֖רֶץ וְכׇל־צְבָאָֽם׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, ב׳","pasuk":"וַיְכַ֤ל אֱלֹהִים֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מְלַאכְתּ֖וֹ אֲשֶׁ֣ר עָשָׂ֑ה וַיִּשְׁבֹּת֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מִכׇּל־מְלַאכְתּ֖וֹ אֲשֶׁ֥ר עָשָֽׂה׃","rashi":[{"d":"ויכל אלהים ביום השביעי","t":"ר' שמעון אומר בשר ודם, שאינו יודע עתיו ורגעיו צריך להוסיף מחל על הקדש, הקב\"ה שיודע עתיו ורגעיו, נכנס בו כחוט השערה, ונראה כאלו כלה בו ביום. ד\"א מה היה העולם חסר? מנוחה, באת שבת באת מנוחה, כלתה ונגמרה המלאכה:"}]},{"ref":"בְּרֵאשִׁית ב׳, ג׳","pasuk":"וַיְבָ֤רֶךְ אֱלֹהִים֙ אֶת־י֣וֹם הַשְּׁבִיעִ֔י וַיְקַדֵּ֖שׁ אֹת֑וֹ כִּ֣י ב֤וֹ שָׁבַת֙ מִכׇּל־מְלַאכְתּ֔וֹ אֲשֶׁר־בָּרָ֥א אֱלֹהִ֖ים לַעֲשֽׂוֹת׃&nbsp;{פ}","rashi":[{"d":"ויברך, ויקדש","t":"ברכו במן, שכל ימות השבוע יורד להם עמר לגלגלת, ובששי לחם משנה, וקדשו במן, שלא ירד כלל בשבת, והמקרא כתוב על העתיד:"},{"d":"אשר ברא אלהים לעשות","t":"המלאכה שהיתה ראויה לעשות בשבת, כפל ועשאה בששי כמו שמפרש בב\"ר:"}]},{"ref":"בְּרֵאשִׁית ב׳, ד׳","pasuk":"אֵ֣לֶּה תוֹלְד֧וֹת הַשָּׁמַ֛יִם וְהָאָ֖רֶץ בְּהִבָּֽרְאָ֑ם בְּי֗וֹם עֲשׂ֛וֹת יְהֹוָ֥ה אֱלֹהִ֖ים אֶ֥רֶץ וְשָׁמָֽיִם׃","rashi":[{"d":"אלה","t":"האמורים למעלה:"},{"d":"תולדות השמים והארץ בהבראם ביום עשות ה'","t":"למדך שכלם נבראו בראשון. דבר אחר בהבראם, בה' בראם, שנ' ביה ה' צור עולמים (ישעיהו כ\"ו), בב' אותיות הללו של השם יצר שני עולמים, ולמדך כאן שהעולם הזה נברא בה\"א, רמז שירדו למטה לראות שחת כה\"א זאת שסתומה מכל צדדים ופתוחה למטה לרדת דרך שם:"}]},{"ref":"בְּרֵאשִׁית ב׳, ה׳","pasuk":"וְכֹ֣ל&thinsp;׀ שִׂ֣יחַ הַשָּׂדֶ֗ה טֶ֚רֶם יִֽהְיֶ֣ה בָאָ֔רֶץ וְכׇל־עֵ֥שֶׂב הַשָּׂדֶ֖ה טֶ֣רֶם יִצְמָ֑ח כִּי֩ לֹ֨א הִמְטִ֜יר יְהֹוָ֤ה אֱלֹהִים֙ עַל־הָאָ֔רֶץ וְאָדָ֣ם אַ֔יִן לַֽעֲבֹ֖ד אֶת־הָֽאֲדָמָֽה׃","rashi":[{"d":"כי לא המטיר","t":"ומ\"ט לא המטיר? לפי שאדם אין לעבד את האדמה, ואין מכיר בטובתם של גשמים, וכשבא אדם וידע שהם צרך לעולם, התפלל עליהם וירדו וצמחו האילנות והדשאים:"},{"d":"ה' אלהים","t":"ה' הוא שמו, אלהים שהוא שליט ושופט על כל, וכן פרוש זה בכל מקום לפי פשוטו, ה' שהוא אלהים:"}]},{"ref":"בְּרֵאשִׁית ב׳, ו׳","pasuk":"וְאֵ֖ד יַֽעֲלֶ֣ה מִן־הָאָ֑רֶץ וְהִשְׁקָ֖ה אֶֽת־כׇּל־פְּנֵ֥י הָֽאֲדָמָֽה׃","rashi":[{"d":"ואד יעלה","t":"לענין בריאתו של אדם, העלה התהום והשקה עננים לשרות העפר ונברא אדם, כגבל זה, שנותן מים ואח\"כ לש את העסה, אף כאן, והשקה, ואח\"כ וייצר:"}]},{"ref":"בְּרֵאשִׁית ב׳, ז׳","pasuk":"וַיִּ֩יצֶר֩ יְהֹוָ֨ה אֱלֹהִ֜ים אֶת־הָֽאָדָ֗ם עָפָר֙ מִן־הָ֣אֲדָמָ֔ה וַיִּפַּ֥ח בְּאַפָּ֖יו נִשְׁמַ֣ת חַיִּ֑ים וַיְהִ֥י הָֽאָדָ֖ם לְנֶ֥פֶשׁ חַיָּֽה׃","rashi":[{"d":"וייצר","t":"שתי יצירות, יצירה לעולם הזה ויצירה לתחית המתים, אבל בבהמה שאינה עומדת לדין לא נכתב ביצירתה שני יודי\"ן:"},{"d":"עפר מן האדמה","t":"צבר עפרו מכל האדמה מארבע רוחות, שכל מקום שימות שם תהא קולטתו לקבורה. ד\"א נטל עפרו ממקום שנאמר בו מזבח אדמה תעשה לי (שמות כ'), הלואי תהיה לו כפרה ויוכל לעמד:"},{"d":"לנפש חיה","t":"אף בהמה וחיה נקראו נפש חיה, אך זו של אדם חיה שבכלן, שנתוסף בו דעה ודבור:"}]},{"ref":"בְּרֵאשִׁית ב׳, ח׳","pasuk":"וַיִּטַּ֞ע יְהֹוָ֧ה אֱלֹהִ֛ים גַּן־בְּעֵ֖דֶן מִקֶּ֑דֶם וַיָּ֣שֶׂם שָׁ֔ם אֶת־הָֽאָדָ֖ם אֲשֶׁ֥ר יָצָֽר׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, ט׳","pasuk":"וַיַּצְמַ֞ח יְהֹוָ֤ה אֱלֹהִים֙ מִן־הָ֣אֲדָמָ֔ה כׇּל־עֵ֛ץ נֶחְמָ֥ד לְמַרְאֶ֖ה וְט֣וֹב לְמַאֲכָ֑ל וְעֵ֤ץ הַֽחַיִּים֙ בְּת֣וֹךְ הַגָּ֔ן וְעֵ֕ץ הַדַּ֖עַת ט֥וֹב וָרָֽע׃","rashi":[{"d":"ויצמח","t":"לענין הגן הכתוב מדבר:"},{"d":"בתוך הגן","t":"באמצע:"}]},{"ref":"בְּרֵאשִׁית ב׳, י׳","pasuk":"וְנָהָר֙ יֹצֵ֣א מֵעֵ֔דֶן לְהַשְׁק֖וֹת אֶת־הַגָּ֑ן וּמִשָּׁם֙ יִפָּרֵ֔ד וְהָיָ֖ה לְאַרְבָּעָ֥ה רָאשִֽׁים׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, י״א","pasuk":"שֵׁ֥ם הָֽאֶחָ֖ד פִּישׁ֑וֹן ה֣וּא הַסֹּבֵ֗ב אֵ֚ת כׇּל־אֶ֣רֶץ הַֽחֲוִילָ֔ה אֲשֶׁר־שָׁ֖ם הַזָּהָֽב׃","rashi":[{"d":"פישון","t":"הוא נילוס נהר מצרים, ועל שם שמימיו מתברכין ועולין ומשקין את הארץ נקרא פישון כמו ופשו פרשיו (חבקוק א') ד\"א פישון, שהוא מגדל פשתן, שנאמר על מצרים (ישעיהו י\"ט) ובשו עבדי פשתים:"}]},{"ref":"בְּרֵאשִׁית ב׳, י״ב","pasuk":"וּֽזְהַ֛ב הָאָ֥רֶץ הַהִ֖וא ט֑וֹב שָׁ֥ם הַבְּדֹ֖לַח וְאֶ֥בֶן הַשֹּֽׁהַם׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, י״ג","pasuk":"וְשֵֽׁם־הַנָּהָ֥ר הַשֵּׁנִ֖י גִּיח֑וֹן ה֣וּא הַסּוֹבֵ֔ב אֵ֖ת כׇּל־אֶ֥רֶץ כּֽוּשׁ׃","rashi":[{"d":"גיחון","t":"שהיה הולך והומה, והמיתו גדולה מאד, כמו כי יגח (שמות כ\"א), שמנגח והולך והומה:"}]},{"ref":"בְּרֵאשִׁית ב׳, י״ד","pasuk":"וְשֵׁ֨ם הַנָּהָ֤ר הַשְּׁלִישִׁי֙ חִדֶּ֔קֶל ה֥וּא הַֽהֹלֵ֖ךְ קִדְמַ֣ת אַשּׁ֑וּר וְהַנָּהָ֥ר הָֽרְבִיעִ֖י ה֥וּא פְרָֽת׃","rashi":[{"d":"חדקל","t":"שמימיו חדין וקלין:"},{"d":"פרת","t":"שמימיו פרין ורבין ומברין את האדם: כוש ואשור. עדין לא היו, וכתב המקרא על שם העתיד:"},{"d":"קדמת אשור","t":"למזרחה של אשור:"}]},{"ref":"בְּרֵאשִׁית ב׳, ט״ו","pasuk":"וַיִּקַּ֛ח יְהֹוָ֥ה אֱלֹהִ֖ים אֶת־הָֽאָדָ֑ם וַיַּנִּחֵ֣הוּ בְגַן־עֵ֔דֶן לְעׇבְדָ֖הּ וּלְשׇׁמְרָֽהּ׃","rashi":[{"d":"ויקח","t":"לקחו בדברים נאים ופתהו לכנס (בראשית רבה):"}]},{"ref":"בְּרֵאשִׁית ב׳, ט״ז","pasuk":"וַיְצַו֙ יְהֹוָ֣ה אֱלֹהִ֔ים עַל־הָֽאָדָ֖ם לֵאמֹ֑ר מִכֹּ֥ל עֵֽץ־הַגָּ֖ן אָכֹ֥ל תֹּאכֵֽל׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, י״ז","pasuk":"וּמֵעֵ֗ץ הַדַּ֙עַת֙ ט֣וֹב וָרָ֔ע לֹ֥א תֹאכַ֖ל מִמֶּ֑נּוּ כִּ֗י בְּי֛וֹם אֲכׇלְךָ֥ מִמֶּ֖נּוּ מ֥וֹת תָּמֽוּת׃","rashi":[]},{"ref":"בְּרֵאשִׁית ב׳, י״ח","pasuk":"וַיֹּ֙אמֶר֙ יְהֹוָ֣ה אֱלֹהִ֔ים לֹא־ט֛וֹב הֱי֥וֹת הָֽאָדָ֖ם לְבַדּ֑וֹ אֶֽעֱשֶׂה־לּ֥וֹ עֵ֖זֶר כְּנֶגְדּֽוֹ׃","rashi":[{"d":"לא טוב היות וגו'","t":"שלא יאמרו שתי רשויות הן, הקב\"ה יחיד בעליונים ואין לו זוג, וזה יחיד בתחתונים ואין לו זוג (בראשית רבה):"},{"d":"עזר כנגדו","t":"זכה – עזר; לא זכה – כנגדו להלחם:"}]},{"ref":"בְּרֵאשִׁית ב׳, י״ט","pasuk":"וַיִּ֩צֶר֩ יְהֹוָ֨ה אֱלֹהִ֜ים מִן־הָֽאֲדָמָ֗ה כׇּל־חַיַּ֤ת הַשָּׂדֶה֙ וְאֵת֙ כׇּל־ע֣וֹף הַשָּׁמַ֔יִם וַיָּבֵא֙ אֶל־הָ֣אָדָ֔ם לִרְא֖וֹת מַה־יִּקְרָא־ל֑וֹ וְכֹל֩ אֲשֶׁ֨ר יִקְרָא־ל֧וֹ הָֽאָדָ֛ם נֶ֥פֶשׁ חַיָּ֖ה ה֥וּא שְׁמֽוֹ׃","rashi":[{"d":"וכל אשר יקרא לו האדם נפש חיה וגו'","t":"סרסהו ופרשהו, כל נפש חיה אשר יקרא לו האדם שם, הוא שמו לעולם:"}]},{"ref":"בְּרֵאשִׁית ב׳, כ׳","pasuk":"וַיִּקְרָ֨א הָֽאָדָ֜ם שֵׁמ֗וֹת לְכׇל־הַבְּהֵמָה֙ וּלְע֣וֹף הַשָּׁמַ֔יִם וּלְכֹ֖ל חַיַּ֣ת הַשָּׂדֶ֑ה וּלְאָדָ֕ם לֹֽא־מָצָ֥א עֵ֖זֶר כְּנֶגְדּֽוֹ׃","rashi":[{"d":"ולאדם לא מצא עזר. ויפל ה' אלהים תרדמה","t":"כשהביאן הביאן לפניו כל מין ומין זכר ונקבה, אמר לכלם יש בן זוג ולי אין בן זוג, מיד ויפל (בראשית רבה):"}]},{"ref":"בְּרֵאשִׁית ב׳, כ״א","pasuk":"וַיַּפֵּל֩ יְהֹוָ֨ה אֱלֹהִ֧ים&thinsp;׀&thinsp;תַּרְדֵּמָ֛ה עַל־הָאָדָ֖ם וַיִּישָׁ֑ן וַיִּקַּ֗ח אַחַת֙ מִצַּלְעֹתָ֔יו וַיִּסְגֹּ֥ר בָּשָׂ֖ר תַּחְתֶּֽנָּה׃","rashi":[{"d":"מצלעותיו","t":"מסטריו, כמו ולצלע המשכן (שמות כ\"ו), זהו שאמרו שני פרצופים נבראו (עירובין י\"ז):"},{"d":"ויסגור","t":"מקום החתך:"},{"d":"ויישן ויקח","t":"שלא יראה חתיכת הבשר שממנו נבראת ותתבזה עליו:"}]},{"ref":"בְּרֵאשִׁית ב׳, כ״ב","pasuk":"וַיִּ֩בֶן֩ יְהֹוָ֨ה אֱלֹהִ֧ים&thinsp;׀&thinsp;אֶֽת־הַצֵּלָ֛ע אֲשֶׁר־לָקַ֥ח מִן־הָֽאָדָ֖ם לְאִשָּׁ֑ה וַיְבִאֶ֖הָ אֶל־הָֽאָדָֽם׃","rashi":[{"d":"ויבן","t":"כבנין, רחבה מלמטה וקצרה מלמעלה לקבל הולד כאוצר של חטים, שהוא רחב מלמטה וקצר מלמעלה שלא יכביד משאו על קירותיו:"},{"d":"ויבן את הצלע לאשה","t":"להיות אשה, כמו ויעש אותו גדעון לאפוד (שופטים ח'), להיות אפוד:"}]},{"ref":"בְּרֵאשִׁית ב׳, כ״ג","pasuk":"וַיֹּ֘אמֶר֮ הָֽאָדָם֒ זֹ֣את הַפַּ֗עַם עֶ֚צֶם מֵֽעֲצָמַ֔י וּבָשָׂ֖ר מִבְּשָׂרִ֑י לְזֹאת֙ יִקָּרֵ֣א אִשָּׁ֔ה כִּ֥י מֵאִ֖ישׁ לֻֽקְחָה־זֹּֽאת׃","rashi":[{"d":"זאת הפעם","t":"מלמד שבא אדם על כל בהמה וחיה, ולא נתקררה דעתו בהם (יבמות ס\"ג):"},{"d":"לזאת יקרא אשה כי מאיש וגו'","t":"לשון נופל על לשון מכאן שנברא העולם בלשון הקדש (בראשית רבה):"}]},{"ref":"בְּרֵאשִׁית ב׳, כ״ד","pasuk":"עַל־כֵּן֙ יַֽעֲזׇב־אִ֔ישׁ אֶת־אָבִ֖יו וְאֶת־אִמּ֑וֹ וְדָבַ֣ק בְּאִשְׁתּ֔וֹ וְהָי֖וּ לְבָשָׂ֥ר אֶחָֽד׃","rashi":[{"d":"על כן יעזב איש","t":"רוח הקדש אומרה כן לאסר על בני נח העריות (סנהדרין נ\"ז):"},{"d":"לבשר אחד","t":"הולד נוצר על ידי שניהם ושם נעשה בשרם אחד (שם נ\"ח):"}]},{"ref":"בְּרֵאשִׁית ב׳, כ״ה","pasuk":"וַיִּֽהְי֤וּ שְׁנֵיהֶם֙ עֲרוּמִּ֔ים הָֽאָדָ֖ם וְאִשְׁתּ֑וֹ וְלֹ֖א יִתְבֹּשָֽׁשׁוּ׃","rashi":[{"d":"ולא יתבוששו","t":"שלא היו יודעים דרך צניעות להבחין בין טוב לרע, ואע\"פ שנתנה בו דעה לקרות לו שמות, לא נתן בו יצר הרע עד אכלו מן העץ ונכנס בו יצר הרע וידע מה בין טוב לרע (בראשית רבה):"}]}]},{"n":"ג","units":[{"ref":"בְּרֵאשִׁית ג׳, א׳","pasuk":"וְהַנָּחָשׁ֙ הָיָ֣ה עָר֔וּם מִכֹּל֙ חַיַּ֣ת הַשָּׂדֶ֔ה אֲשֶׁ֥ר עָשָׂ֖ה יְהֹוָ֣ה אֱלֹהִ֑ים וַיֹּ֙אמֶר֙ אֶל־הָ֣אִשָּׁ֔ה אַ֚ף כִּֽי־אָמַ֣ר אֱלֹהִ֔ים לֹ֣א תֹֽאכְל֔וּ מִכֹּ֖ל עֵ֥ץ הַגָּֽן׃","rashi":[{"d":"והנחש היה ערום","t":"מה ענין זה לכאן? היה לו לסמך ויעש לאדם ולאשתו כתנות עור וילבשם, אלא למדך מאיזו עצה קפץ הנחש עליהם, ראה אותם ערמים ועוסקים בתשמיש לעין כל ונתאוה לה:"},{"d":"ערום מכל","t":"לפי ערמתו וגדלתו היתה מפלתו, ערום מכל, ארור מכל (בראשית רבה):"},{"d":"אף כי אמר וגו'","t":"שמא אמר לכם לא תאכלו מכל וגו', ואע\"פ שראה אותם אוכלים משאר פרות, הרבה עליה דברים כדי שתשיבנו ויבא לדבר באותו העץ:"}]},{"ref":"בְּרֵאשִׁית ג׳, ב׳","pasuk":"וַתֹּ֥אמֶר הָֽאִשָּׁ֖ה אֶל־הַנָּחָ֑שׁ מִפְּרִ֥י עֵֽץ־הַגָּ֖ן נֹאכֵֽל׃","rashi":[]},{"ref":"בְּרֵאשִׁית ג׳, ג׳","pasuk":"וּמִפְּרִ֣י הָעֵץ֮ אֲשֶׁ֣ר בְּתוֹךְ־הַגָּן֒ אָמַ֣ר אֱלֹהִ֗ים לֹ֤א תֹֽאכְלוּ֙ מִמֶּ֔נּוּ וְלֹ֥א תִגְּע֖וּ בּ֑וֹ פֶּן־תְּמֻתֽוּן׃","rashi":[{"d":"ולא תגעו בו","t":"הוסיפה על הצווי, לפיכך באה לידי גרעון, הוא שנאמר אל תוסף על דבריו (משלי ל'):"}]},{"ref":"בְּרֵאשִׁית ג׳, ד׳","pasuk":"וַיֹּ֥אמֶר הַנָּחָ֖שׁ אֶל־הָֽאִשָּׁ֑ה לֹֽא־מ֖וֹת תְּמֻתֽוּן׃","rashi":[{"d":"לא מות תמותון","t":"דחפה עד שנגעה בו, אמר לה כשם שאין מיתה בנגיעה, כך אין מיתה באכילה (בראשית רבה):"}]},{"ref":"בְּרֵאשִׁית ג׳, ה׳","pasuk":"כִּ֚י יֹדֵ֣עַ אֱלֹהִ֔ים כִּ֗י בְּיוֹם֙ אֲכׇלְכֶ֣ם מִמֶּ֔נּוּ וְנִפְקְח֖וּ עֵֽינֵיכֶ֑ם וִהְיִיתֶם֙ כֵּֽאלֹהִ֔ים יֹדְעֵ֖י ט֥וֹב וָרָֽע׃","rashi":[{"d":"כי ידע","t":"כל אמן שונא את בני אמנותו, מן העץ אכל וברא את העולם (בראשית רבה):"},{"d":"והייתם כאלהים","t":"יוצרי עולמות (בראשית רבה):"}]},{"ref":"בְּרֵאשִׁית ג׳, ו׳","pasuk":"וַתֵּ֣רֶא הָֽאִשָּׁ֡ה כִּ֣י טוֹב֩ הָעֵ֨ץ לְמַאֲכָ֜ל וְכִ֧י תַֽאֲוָה־ה֣וּא לָעֵינַ֗יִם וְנֶחְמָ֤ד הָעֵץ֙ לְהַשְׂכִּ֔יל וַתִּקַּ֥ח מִפִּרְי֖וֹ וַתֹּאכַ֑ל וַתִּתֵּ֧ן גַּם־לְאִישָׁ֛הּ עִמָּ֖הּ וַיֹּאכַֽל׃","rashi":[{"d":"ותרא האשה","t":"ראתה דבריו של נחש והנאו לה והאמינתו (בראשית רבה):"},{"d":"כי טוב העץ","t":"להיות כאלהים:"},{"d":"וכי תאוה הוא לעינים","t":"כמו שאמר לה ונפקחו עיניכם:"}]},{"ref":"בְּרֵאשִׁית ג׳, ז׳","pasuk":"וַתִּפָּקַ֙חְנָה֙ עֵינֵ֣י שְׁנֵיהֶ֔ם וַיֵּ֣דְע֔וּ כִּ֥י עֵֽירֻמִּ֖ם הֵ֑ם וַֽיִּתְפְּרוּ֙ עֲלֵ֣ה תְאֵנָ֔ה וַיַּעֲשׂ֥וּ לָהֶ֖ם חֲגֹרֹֽת׃","rashi":[{"d":"ותפקחנה וגו'","t":"לענין החכמה דבר הכתוב ולא לענין ראיה ממש, וסוף המקרא מוכיח:"},{"d":"וידעו כי עירמים הם","t":"אף הסומא יודע כשהוא ערום, אלא מהו וידעו כי עירמם הם? מצוה אחת היתה בידם ונתערטלו הימנה (בראשית רבה):"},{"d":"עלה תאנה","t":"הוא העץ שאכלו ממנו, בדבר שנתקלקלו בו נתקנו (סנהדרין ע'), אבל שאר העצים מנעום מלטל עליהם. ומפני מה לא נתפרסם העץ? שאין הקב\"ה חפץ להונות בריה, שלא יכלימוה ויאמרו זהו שלקה העולם על ידו, מדרש רבי תנחומא:"}]},{"ref":"בְּרֵאשִׁית ג׳, ח׳","pasuk":"וַֽיִּשְׁמְע֞וּ אֶת־ק֨וֹל יְהֹוָ֧ה אֱלֹהִ֛ים מִתְהַלֵּ֥ךְ בַּגָּ֖ן לְר֣וּחַ הַיּ֑וֹם וַיִּתְחַבֵּ֨א הָֽאָדָ֜ם וְאִשְׁתּ֗וֹ מִפְּנֵי֙ יְהֹוָ֣ה אֱלֹהִ֔ים בְּת֖וֹךְ עֵ֥ץ הַגָּֽן׃","rashi":[{"d":"וישמעו","t":"יש מדרשי אגדה רבים וכבר סדרום רבותינו על מכונם בב\"ר ובשאר מדרשות; ואני לא באתי אלא לפשוטו של מקרא ולאגדה המישבת דברי המקרא דבר דבור על אפניו: וישמעו. מה שמעו? שמעו את קול הקב\"ה שהיה מתהלך בגן:"},{"d":"לרוח היום","t":"לאותו רוח שהשמש באה לשם, וזו היא מערבית; שלפנות ערב חמה במערב, והם סרחו בעשירית (סנהדרין ל\"ח):"}]},{"ref":"בְּרֵאשִׁית ג׳, ט׳","pasuk":"וַיִּקְרָ֛א יְהֹוָ֥ה אֱלֹהִ֖ים אֶל־הָֽאָדָ֑ם וַיֹּ֥אמֶר ל֖וֹ אַיֶּֽכָּה׃","rashi":[{"d":"איכה","t":"יודע היה היכן הוא אלא לכנס עמו בדברים, שלא יהא נבהל להשיב אם יענישהו פתאום (בראשית רבה), וכן בקין אמר לו אי הבל אחיך (בראשית ד), וכן בבלעם מי האנשים האלה עמך (במדבר כ\"ב), לכנס עמהם בדברים, וכן בחזקיה בשלוחי מראדך בלאדן:"}]},{"ref":"בְּרֵאשִׁית ג׳, י׳","pasuk":"וַיֹּ֕אמֶר אֶת־קֹלְךָ֥ שָׁמַ֖עְתִּי בַּגָּ֑ן וָאִירָ֛א כִּֽי־עֵירֹ֥ם אָנֹ֖כִי וָאֵחָבֵֽא׃","rashi":[]},{"ref":"בְּרֵאשִׁית ג׳, י״א","pasuk":"וַיֹּ֕אמֶר מִ֚י הִגִּ֣יד לְךָ֔ כִּ֥י עֵירֹ֖ם אָ֑תָּה הֲמִן־הָעֵ֗ץ אֲשֶׁ֧ר צִוִּיתִ֛יךָ לְבִלְתִּ֥י אֲכׇל־מִמֶּ֖נּוּ אָכָֽלְתָּ׃","rashi":[{"d":"מי הגיד לך","t":"מאין לך לדעת מה בשת יש בעומד ערם?"},{"d":"המן העץ","t":"בתמיה:"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ב","pasuk":"וַיֹּ֖אמֶר הָֽאָדָ֑ם הָֽאִשָּׁה֙ אֲשֶׁ֣ר נָתַ֣תָּה עִמָּדִ֔י הִ֛וא נָֽתְנָה־לִּ֥י מִן־הָעֵ֖ץ וָאֹכֵֽל׃","rashi":[{"d":"אשר נתתה עמדי","t":"כאן כפר בטובה (עבודה זרה ה):"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ג","pasuk":"וַיֹּ֨אמֶר יְהֹוָ֧ה אֱלֹהִ֛ים לָאִשָּׁ֖ה מַה־זֹּ֣את עָשִׂ֑ית וַתֹּ֙אמֶר֙ הָֽאִשָּׁ֔ה הַנָּחָ֥שׁ הִשִּׁיאַ֖נִי וָאֹכֵֽל׃","rashi":[{"d":"השיאני","t":"הטעני, כמו אל ישיא אתכם חזקיהו (דברי הימים ב' ל\"ב):"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ד","pasuk":"וַיֹּ֩אמֶר֩ יְהֹוָ֨ה אֱלֹהִ֥ים&thinsp;׀&thinsp;אֶֽל־הַנָּחָשׁ֮ כִּ֣י עָשִׂ֣יתָ זֹּאת֒ אָר֤וּר אַתָּה֙ מִכׇּל־הַבְּהֵמָ֔ה וּמִכֹּ֖ל חַיַּ֣ת הַשָּׂדֶ֑ה עַל־גְּחֹנְךָ֣ תֵלֵ֔ךְ וְעָפָ֥ר תֹּאכַ֖ל כׇּל־יְמֵ֥י חַיֶּֽיךָ׃","rashi":[{"d":"כי עשית זאת","t":"מכאן שאין מהפכים בזכותו של מסית, שאלו שאלו למה עשית זאת? היה לו להשיב דברי הרב ודברי התלמיד דברי מי שומעין? (סנהדרין כ\"ט):"},{"d":"מכל הבהמה ומכל חית השדה","t":"אם מבהמה נתקלל מחיה לא כל שכן, העמידו רבותינו מדרש זה במסכת בכורות (דף ח') ללמד שימי עבורו של נחש שבע שנים:"},{"d":"על גחונך תלך","t":"רגלים היו לו ונקצצו:"}]},{"ref":"בְּרֵאשִׁית ג׳, ט״ו","pasuk":"וְאֵיבָ֣ה&thinsp;׀ אָשִׁ֗ית בֵּֽינְךָ֙ וּבֵ֣ין הָֽאִשָּׁ֔ה וּבֵ֥ין זַרְעֲךָ֖ וּבֵ֣ין זַרְעָ֑הּ ה֚וּא יְשׁוּפְךָ֣ רֹ֔אשׁ וְאַתָּ֖ה תְּשׁוּפֶ֥נּוּ עָקֵֽב׃&nbsp;{ס}&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;","rashi":[{"d":"ואיבה אשית","t":"אתה לא נתכונת אלא שימות אדם כשיאכל הוא תחלה ותשא את חוה, ולא באת לדבר אל חוה תחלה אלא לפי שהנשים קלות להתפתות ויודעות לפתות את בעליהן, לפיכך ואיבה אשית:"},{"d":"ישופך","t":"יכתתך (סוטה ט') כמו ואכת אתו (דברים ט), ותרגומו ושפית יתי':"},{"d":"ואתה תשופנו עקב","t":"לא יהא לך קומה ותשכנו בעקבו, ואף משם תמיתנו, ולשון תשופנו כמו נשף בהם (ישעיהו מ') כשהנחש בא לנשך הוא נושף כמין שריקה ולפי שהלשון נופל על הלשון כתיב לשון נשיפה בשניהם:"}]},{"ref":"בְּרֵאשִׁית ג׳, ט״ז","pasuk":"אֶֽל־הָאִשָּׁ֣ה אָמַ֗ר הַרְבָּ֤ה אַרְבֶּה֙ עִצְּבוֹנֵ֣ךְ וְהֵֽרֹנֵ֔ךְ בְּעֶ֖צֶב תֵּֽלְדִ֣י בָנִ֑ים וְאֶל־אִישֵׁךְ֙ תְּשׁ֣וּקָתֵ֔ךְ וְה֖וּא יִמְשׇׁל־בָּֽךְ׃&nbsp;{ס}&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;","rashi":[{"d":"עצבונך","t":"זה צער גדול בנים (עירובין ק'):"},{"d":"והרנך","t":"זה צער העבור:"},{"d":"בעצב תלדי בנים","t":"זה צער הלדה:"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ז","pasuk":"וּלְאָדָ֣ם אָמַ֗ר כִּֽי־שָׁמַ֘עְתָּ֮ לְק֣וֹל אִשְׁתֶּ֒ךָ֒ וַתֹּ֙אכַל֙ מִן־הָעֵ֔ץ אֲשֶׁ֤ר צִוִּיתִ֙יךָ֙ לֵאמֹ֔ר לֹ֥א תֹאכַ֖ל מִמֶּ֑נּוּ אֲרוּרָ֤ה הָֽאֲדָמָה֙ בַּֽעֲבוּרֶ֔ךָ בְּעִצָּבוֹן֙ תֹּֽאכְלֶ֔נָּה כֹּ֖ל יְמֵ֥י חַיֶּֽיךָ׃","rashi":[{"d":"ארורה האדמה בעבורך","t":"מעלה לך דברים ארורים, כגון זבובים, פרעושים ונמלים, משל ליוצא לתרבות רעה והבריות מקללות שדים שינק מהם:"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ח","pasuk":"וְק֥וֹץ וְדַרְדַּ֖ר תַּצְמִ֣יחַֽ לָ֑ךְ וְאָכַלְתָּ֖ אֶת־עֵ֥שֶׂב הַשָּׂדֶֽה׃","rashi":[{"d":"וקוץ ודרדר תצמיח לך","t":"הארץ כשתזרענה מיני זרעים, תצמיח קוץ ודרדר קנדס ועכביות, והן נאכלין על ידי תקון (ביצה ל\"ד):"}]},{"ref":"בְּרֵאשִׁית ג׳, י״ט","pasuk":"בְּזֵעַ֤ת אַפֶּ֙יךָ֙ תֹּ֣אכַל לֶ֔חֶם עַ֤ד שֽׁוּבְךָ֙ אֶל־הָ֣אֲדָמָ֔ה כִּ֥י מִמֶּ֖נָּה לֻקָּ֑חְתָּ כִּֽי־עָפָ֣ר אַ֔תָּה וְאֶל־עָפָ֖ר תָּשֽׁוּב׃","rashi":[{"d":"בזעת אפיך","t":"לאחר שתטרח בו הרבה:"}]},{"ref":"בְּרֵאשִׁית ג׳, כ׳","pasuk":"וַיִּקְרָ֧א הָֽאָדָ֛ם שֵׁ֥ם אִשְׁתּ֖וֹ חַוָּ֑ה כִּ֛י הִ֥וא הָֽיְתָ֖ה אֵ֥ם כׇּל־חָֽי׃","rashi":[{"d":"חוה","t":"נופל על לשון חיה, שמחיה את ולדותיה, כאשר תאמר מה הוה לאדם (קהלת ב'), בלשון היה:"}]},{"ref":"בְּרֵאשִׁית ג׳, כ״א","pasuk":"וַיַּ֩עַשׂ֩ יְהֹוָ֨ה אֱלֹהִ֜ים לְאָדָ֧ם וּלְאִשְׁתּ֛וֹ כׇּתְנ֥וֹת ע֖וֹר וַיַּלְבִּשֵֽׁם׃&nbsp;{פ}","rashi":[{"d":"כתנות עור","t":"יש דברי אגדה אומרים חלקים כצפרן היו מדבקים על עורן וי\"א דבר הבא מן העור, כגון צמר הארנבים שהוא רך וחם ועשה להם כתנות ממנו:"}]},{"ref":"בְּרֵאשִׁית ג׳, כ״ב","pasuk":"וַיֹּ֣אמֶר&thinsp;׀ יְהֹוָ֣ה אֱלֹהִ֗ים הֵ֤ן הָֽאָדָם֙ הָיָה֙ כְּאַחַ֣ד מִמֶּ֔נּוּ לָדַ֖עַת ט֣וֹב וָרָ֑ע וְעַתָּ֣ה&thinsp;׀ פֶּן־יִשְׁלַ֣ח יָד֗וֹ וְלָקַח֙ גַּ֚ם מֵעֵ֣ץ הַֽחַיִּ֔ים וְאָכַ֖ל וָחַ֥י לְעֹלָֽם׃","rashi":[{"d":"היה כאחד ממנו","t":"הרי הוא יחיד בתחתונים כמו שאני יחיד בעליונים, ומה היא יחידותו? לדעת טוב ורע, מה שאין כן בבהמה וחיה"},{"d":"ועתה פן ישלח ידו","t":"ומשיחיה לעולם הרי הוא קרוב להטעות הבריות אחריו, ולומר אף הוא אלוה. ויש מדרשי אגדה, אבל אין מישבין על פשוטו:"}]},{"ref":"בְּרֵאשִׁית ג׳, כ״ג","pasuk":"וַֽיְשַׁלְּחֵ֛הוּ יְהֹוָ֥ה אֱלֹהִ֖ים מִגַּן־עֵ֑דֶן לַֽעֲבֹד֙ אֶת־הָ֣אֲדָמָ֔ה אֲשֶׁ֥ר לֻקַּ֖ח מִשָּֽׁם׃","rashi":[]},{"ref":"בְּרֵאשִׁית ג׳, כ״ד","pasuk":"וַיְגָ֖רֶשׁ אֶת־הָֽאָדָ֑ם וַיַּשְׁכֵּן֩ מִקֶּ֨דֶם לְגַן־עֵ֜דֶן אֶת־הַכְּרֻבִ֗ים וְאֵ֨ת לַ֤הַט הַחֶ֙רֶב֙ הַמִּתְהַפֶּ֔כֶת לִשְׁמֹ֕ר אֶת־דֶּ֖רֶךְ עֵ֥ץ הַֽחַיִּֽים׃&nbsp;{ס}&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;","rashi":[{"d":"מקדם לגן עדן","t":"במזרחו של גן עדן חוץ לגן:"},{"d":"את הכרובים","t":"מלאכי חבלה:"},{"d":"החרב המתהפכת","t":"ולה להט לאים עליו מלכנס עוד לגן תרגום להט שנן, כמו שלף שננא ובלשון לעז לא\"מא ומדרשי אגדה יש, ואני איני בא אלא לפשוטו:"}]}]}]},"halacha":{"id":"halacha","kind":"halacha","title":"שֻׁלְחָן עָרוּךְ · אֹרַח חַיִּים","sub":"סִימָנִים א׳–י״ב · עִם מִשְׁנָה בְּרוּרָה","icon":"📔","simanim":[{"n":"א","title":"דִּין הַשְׁכָּמַת הַבֹּקֶר","seifim":[{"n":1,"sa":"יתגבר כארי לעמוד בבוקר לעבודת בוראו שיהא הוא מעורר השחר: הגה ועכ\"פ לא יאחר זמן התפלה שהצבור מתפללין (טור). הגה שויתי ה' לנגדי תמיד הוא כלל גדול בתורה ובמעלות הצדיקים אשר הולכים לפני האלהים כי אין ישיבת האדם ותנועותיו ועסקיו והוא לבדו בביתו כישיבתו ותנועותיו ועסקיו והוא לפני מלך גדול ולא דבורו והרחבת פיו כרצונו והוא עם אנשי ביתו וקרוביו כדבורו במושב המלך כ\"ש כשישים האדם אל לבו שהמלך הגדול הקב\"ה אשר מלא כל הארץ כבודו עומד עליו ורואה במעשיו כמו שנאמר אם יסתר איש במסתרים ואני לא אראנו נאום ה' מיד יגיע אליו הירא' וההכנעה בפחד הש\"י ובושתו ממנו תמיד (מורה נבוכים ח\"ג פ' נ\"ב) ולא יתבייש מפני בני אדם המלעיגים עליו בעבודת הש\"י גם בהצנע לכת ובשכבו על משכבו ידע לפני מי הוא שוכב ומיד כשיעור משנתו יקום בזריזות לעבודת בוראו יתברך ויתעלה (טור):"},{"n":2,"sa":"המשכים להתחנן לפני בוראו יכוין לשעות שמשתנות המשמרות שהן בשליש הלילה ולסוף שני שלישי הלילה ולסוף הלילה שהתפלה שיתפלל באותן השעות על החורבן ועל הגלות רצויה:"},{"n":3,"sa":"ראוי לכל ירא שמים שיהא מיצר ודואג על חורבן בית המקדש:"},{"n":4,"sa":"טוב מעט תחנונים בכוונה מהרבות בלא כוונה:"},{"n":5,"sa":"טוב לומר פ' העקדה ופ' המן ועשרת הדברות ופרשת עולה ומנחה ושלמים וחטאת ואשם: הגה ודוקא ביחיד מותר לומר י' הדברות בכל יום אבל אסור לאומרם בצבור (תשו' הרשב\"א סימן קפ\"ד):"},{"n":6,"sa":"פרשיות הקרבנות לא יאמר אלא ביום. (וע\"ל סי' מ\"ז סעיף י\"ג) :"},{"n":7,"sa":"כשיסיים פרשת העולה יאמר יהר\"מ שיהא זה חשוב ומקובל כאלו הקרבתי עולה וכך יאמר אחר פ' המנחה והשלמים מפני שהם באים בנדבה:"},{"n":8,"sa":"יאמר עם הקרבנות פ' ושחט אותו על ירך המזבח צפונה לפני ה':"},{"n":9,"sa":"יש נוהגין לומר פ' הכיור ואח\"כ פרשת תרומת הדשן ואח\"כ פ' התמיד ואח\"כ פרשת מזבח מקטר קטורת ופרשת סממני הקטורת ועשייתו:"}],"mb":[{"n":"א","t":"(א) לעבודת בוראו – כי לכך נברא האדם, כמו שאמר הכתוב: \"כל הנקרא בשמי ולכבודי בראתיו\" וגו'. ואף אם ישיאנו יצרו בחורף לומר: איך תעמוד בבוקר, כי הקור גדול; או ישיאנו בקיץ לומר: איך תעמוד ממיטתך, ועדיין לא שבעת משנתך? יתגבר עליו ואל ישמע לו, ויחשוב בנפשו: אילו היה נצרך לעמוד לשרת לפני מלך בשר ודם, כמה היה זהיר וזריז לעמוד בהשכמה להכין עצמו לעבודתו; כל שכן וקל וחומר בן בנו של קל וחומר לפני מלך מלכי המלכים הקדוש ברוך הוא."},{"n":"ב","t":"(ב) השחר – בשל\"ה כתב סוד, לחבר יום ולילה בתורה או בתפילה, הן בבוקר הן בערב. ומיד כשיתעורר משנתו ואינו רוצה לישן, יטול ידיו, אף שנשאר מושכב. ומכל שכן שלא ילך ארבע אמות בלי נטילת ידים. וצריך מאד ליזהר בזה. ובזוהר הקדוש מפליג עבור זה בעונשו למאד, כי הוא משהה על עצמו רוח הטומאה. ומכל מקום, חלילה לעבור שום איסור עבור חסרון נטילת ידיים, כגון לעצור עצמו מלהשתין על ידי זה, או ליקח מים שהכין חבירו עבור עצמו, אם לא שברור לו שיתן תיכף תמורתם אחרים. ויש שנכשלין בזה. אם אירע שהמים רחוקים ואין לו מי שיקרבם אליו, נהגו קצת מבעלי הנפש שהולכים פחות פחות מארבע אמות. וכתב השערי תשובה על זה דלא נהירא, דעדיף יותר שילכו במרוצה, שלא להשהות רוח רעה על ידיו. יש אומרים דלעניין זה אמרינן כולא ביתא כארבע אמות דמי, אבל אין לסמוך על זה כי אם בשעת הדחק. אם אירע כשמשכים בלילה שאין לו מים ליטול ידיו שלוש פעמים כראוי להעביר רוח הטומאה, אף על פי כן חלילה לו לבטל מדברי תורה משום זה עד שיאיר היום, אלא יטול מעט או ינקה ידיו בכל מידי דמנקי ויברך וילמוד, כדין התלמוד והפוסקים."},{"n":"ג","t":"(ג) שהציבור מתפללין – היינו אף על פי שלא יעבור זמן תפילה, מכל מקום מצווה עם הציבור. ועיין לקמן סוף סעיף קטן ט'."},{"n":"ד","t":"(ד) הצדיקים – דהיינו שיצייר בנפשו תמיד איך שהוא עומד לפני השם יתברך, כי הקב\"ה מלא כל הארץ כבודו. וכתבו בשם האר\"י ז\"ל, שיצייר שם הוי\"ה תמיד נגד עיניו בניקוד יראה, כזה י-ה-ו-ה, וזהו סוד \"שויתי ה' לנגדי תמיד\", וזה תועלת גדול לענין היראה. ויש שהיו רגילין מחמת זה לעשות מנורות של קלף מצויירים להניח בסידורים, וכותבים בהם \"שויתי ה'\" וגו' בן ארבע אותיות ושארי שמות, ומנורה כזה היתה נקראת בשם \"שויתי\". והטעם הוא בכדי שיהיה נזכר שלא לשיח שיחה בטלה בתוך התפלה מאימת השם. וכתב בשערי תשובה בשם התבואת שור שראוי לאזור חיל לבטל המנהג, כי על פי הרוב אינם משמרים את הקלף כראוי, ותשתפכנה בראש כל חוצות, וגם כמה פעמים בא לידי מחיקת השם. ונראה דבמנורות הגדולות המצויירות על קלף שקובעים בבית הכנסת לפני העמוד תחת טבלא של זכוכית, שאין שייך בזה טעם הנ\"ל, לית לן בה, עד כאן לשונו. והקובעין בעמוד בלא טבלא יש למחות בידם, כי על ידי הנרות שקובעין בעמוד, בא ברוב העיתים לידי מחיקת השם חס ושלום."},{"n":"ה","t":"(ה) מפני בני אדם – ועל כל פנים לא יתקוטט עמהם, מפני שמידת העזות מגונה מאד, ואין ראוי להשתמש ממנה כלל, אפילו בעבודת השם יתברך, כי יקנה קניין בנפשו להיות עז אפילו שלא במקום עבודתו יתברך (ב\"י). ועיין בביאור הלכה."},{"n":"ו","t":"(ו) המלעיגים עליו – וכן אם הוא אדם בינוני עומד במקום גדולים, לא יתבייש מהם ללמוד ולעשות המצווה. אך אם אפשר לו לעשות המצווה שלא בפניהם, טוב יותר. ומיהו בפני בינונים שילמדו ממנו, יש לומר, טוב יותר לעשות בפניהם, שילמדו ממנו לעשות כמעשהו. אך יכוין לבו לשם שמים, ולא להתפאר חלילה."},{"n":"ז","t":"(ז) גם בהצנע לכת – רוצה לומר, אף בשעה שהוא בביתו בהצנע, גם כן יהיה לכתו עם ה' אלהיו, וכמו שמסיים והולך."},{"n":"ח","t":"(ח) בזריזות – לאו דווקא, אלא ישהה מעט ולא יעמוד פתאום, כי זה מזיק לגוף [גיטין דף ע']. טוב לומר תיכף בקומו: \"מודה אני לפניך מלך חי וקיים שהחזרת בי נשמתי בחמלה, רבה אמונתך\". ותיבת \"בחמלה\" יהיה באתנחתא, ו\"רבה אמונתך\" בלי הפסק. והוא מן הכתוב: \"חדשים לבקרים\" וגו', שהקב\"ה מקיים אמונתו להחזיר נשמות המופקדים בבוקר. ואין צריך לזה נטילת ידיים, ואף אם ידיו מטונפות, כי אין מזכיר בזה הנוסח לא שם ולא כינוי. ומכל מקום ללמוד נראה דאסור קודם שנטל ידיו, ובלאו הכי אסור קודם ברכת התורה. ועיין לעיל סוף ס\"ק ב'. סעיף ג [עריכה]"}]},{"n":"ב","title":"דִּינֵי לְבִישַׁת הַבְּגָדִים","seifim":[{"n":1,"sa":"לא ילבש חלוקו מיושב ( טור) אלא יקח חלוקו ויכניס בו (ראשו) וזרועותיו בעודנו שוכב ונמצא כשיקום שהוא מכוסה:"},{"n":2,"sa":"אל יאמר הנני בחדרי חדרים מי רואני כי הקב\"ה מלא כל הארץ כבודו:"},{"n":3,"sa":"ידקדק בחלוקו ללובשו כדרכו שלא יהפוך הפנימי לחוץ:"},{"n":4,"sa":"ינעול מנעל ימין תחלה ולא יקשרנו ואח\"כ ינעול של שמאל ויקשרנו ויחזור ויקשור של ימין: הגה ובמנעלי' שלנו שאין להם קשירה ינעול של ימין תחל' (תוס' פ' במה אשה דס\"א):"},{"n":5,"sa":"כשחולץ מנעליו חולץ של שמאל תחלה:"},{"n":6,"sa":"אסור לילך בקומה זקופה ולא ילך ד' אמות בגילוי הראש ויבדוק נקביו: הגה ויכסה כל גופו ולא ילך יחף (א\"ז) וירגיל עצמו לפנות בוקר וערב שהוא זריזות ונקיות (הגהות מיימוני פ' ה' מה' דעות):"}],"mb":[{"n":"א","t":"(א) מיושב - דאז בהכרח יתגלה גופו והאדם צריך להתנהג בצניעות ובושה לפני הקב\"ה ואפילו כשהוא לילה ובחדרי חדרים הלא מלא כל הארץ כבודו וכחשיכה וכאורה לפניו יתברך. וכן צריך ליזהר תמיד מחמת טעם זה שלא במקום הכרח מלגלות מבשרו ואפילו מעט כל מה שדרכו להיות מכוסה בבגדים לעולם אבל רשאי לגלות ידו עד קוב\"דו וצוארו עד החזה ע\"כ האנפלאות יראה ללבשם או לפשטם ג\"כ תחת הסדין שלא לגלות רגליו שדרכן להיות מכוסות לעולם במדינות אלו שאין הולכין יחף אפילו בקיץ וכן כל כיוצא בזה אם לא שאי אפשר בענין אחר וכן בבית המרחץ שדרכן של בני אדם לילך שם ערומים וא\"א בענין אחר אין בזה משום פריצות וכן כשרוחץ בנהר הדין כן רק יזהר לפשוט וללבוש סמוך לנהר כל מה שאפשר בכדי שלא ילך בגילוי הגוף שלא לצורך ואפילו ערותו א\"צ לכסות בירידתו לנהר ולא עוד אלא שהמכסה נראה כאלו בוש בדבר וכאלו כופר בבריתו של אברהם אבינו אך בעלייתו מן הנהר שפניו כלפי העם ישחה או ישים ידו כנגד ערותו לכסותה ובלבד שלא יגע בה כמו שיתבאר בס\"ס ג'. איתא בש\"ס חלוק של ת\"ח כל שאין בשרו נראית מתחתיו. והאידנא אין נזהרין בזה משום שהולכין הכל בבתי שוקיים ואין הבשר נראית:"},{"n":"ב","t":"(ב) כשיקום - ר\"ל כשיקום ויצא מתחת כיסוי סדינו שהיה מונח שם ערום כשפשט חלוקו יהיה עתה תיכף מכוסה כי יפול חלוקו על כל גופו מעצמו ועיין לקמן סימן רל\"ט ס\"ב לענין פשיטת החלוק. המניח מלבושיו מראשותיו משכח לימודו ואפשר אם מניח דבר אחר המפסיק בין ראשו לבגדיו אין קפידא וכן יזהר מללבוש ב' מלבושים יחד בפ\"א כי קשה לשכחה. הקורא כתב שע\"ג הקבר או המסתכל בפני המת משכח לימודו ועיין עוד בפמ\"ג מדברים המחזירים הלימוד:"},{"n":"ג","t":"(ג) בחלוקו - אע\"פ שהוא תחת כל המלבושים וכ\"ש בשאר בגדים:"},{"n":"ד","t":"(ד) לחוץ - ויראו תפירות המגונות ואמרי החלוק ויתגנה בעיני הבריות ואם לא נזהר והפך אם ת\"ח הוא צריך לפושטו ולחזור ללבשו כדרכו שלא יהיה בכלל משניאי ח\"ו ושאר כל אדם אין צריך ולתפלה אפילו כל אדם צריך לפשטו וללבשו כדרכו שראוי אז להדר בגדיו כמבואר בסימן צ\"א. טוב שישים שני צדי המלבוש ביד ימינו וילבש הימין ואח\"כ השמאל ויכוין כי הכל נכלל בימין ומן הימין בא לשמאל. כתב הרמב\"ם מלבוש ת\"ח יהיה מלבוש נאה ונקי ואסור לו שימצא בבגדו כתם או שמנונית וכיוצא בהם. ולא ילבש לא מלבוש שרים שהכל מסתכלים בהם ולא מלבוש עניים שהוא מבזה את לובשיו אלא בגדים בינונים נאים ע\"ש עוד:"},{"n":"ה","t":"(ה) ימין - שכן מצינו בתורה שהימין חשוב תמיד לענין בוהן יד ורגל ולכל הדברים שמקדימים הימין להשמאל:"},{"n":"ו","t":"(ו) ויקשרנו - דלענין קשירה מצינו שהתורה נתנה חשיבות אל השמאל שקושר עליה תפילה של יד. ובאנפלאות של לבד א\"צ להקדים שמאל לקשירה ואיטר יד שמניח תפילין בימין של כל אדם יקדים ימין גם להקשירה:"},{"n":"ז","t":"(ז) ימין תחלה - וגם אם נזדמן לו של שמאל ימתין עד שיביאו לו של ימין. כשהוא רוחץ וסך ימין תחלה ואם סך כל גופו ראש תחלה מפני שהוא מלך על כל האיברים ועיין בד\"מ:"},{"n":"ח","t":"(ח) חולץ של וכו' - שזהו כבודה של ימין:"}]},{"n":"ג","title":"הַנְהָגַת בֵּית הַכִּסֵּא","seifim":[{"n":1,"sa":"כשיכנס לבה\"כ יאמר התכבדו מכובדים וכו'. ועכשיו לא נהגו לאמרו:"},{"n":2,"sa":"יהא צנוע בבית הכסא ולא יגלה עצמו עד שישב: הגה ולא ילכו שני אנשים ביחד גם לא ידבר שם ויסגור הדלת בעדו משום צניעות. (אור זרוע):"},{"n":3,"sa":"אם רוצה למשמש בפי הטבעת בצרור או בקיסם לפתוח נקביו ימשמש קודם שישב ולא ימשמש אחר שישב מפני שקשה לכשפים:"},{"n":4,"sa":"לא יגלה עצמו כי אם מלאחריו טפח ומלפניו טפחיים ואשה מאחריה טפח ומלפניה ולא כלום:"},{"n":5,"sa":"אם נפנה במקום מגולה שאין בו מחיצות יכוין שיהיו פניו לדרום ואחוריו לצפון או איפכא אבל בין מזרח למערב אסור: (ולהטיל מים בכל ענין שרי) (ב\"י בשם הרמב\"ם):"},{"n":6,"sa":"וכן אסור לישן בין מזרח למערב אם אשתו עמו ונכון להזהר אפילו כשאין אשתו עמו:"},{"n":7,"sa":"המטיל מים מן הצופים ולפנים (פי' מקום שיכולים משם לראות הר הבית ומשם והלאה אין יכולים לראות רש\"י) (לא) ישב ופניו כלפי הקודש (אלא לצפון או לדרום) או יסלק הקודש לצדדין:"},{"n":8,"sa":"כשנפנה בשדה אם הוא אחורי הגדר יפנה מיד ובבקעה יתרחק עד מקום שלא יוכל חבירו לראות פירועו:"},{"n":9,"sa":"לא ישב במהרה ובחוזק ולא יאנוס לדחוק עצמו יותר מדאי שלא ינתק שיני הכרכשתא:"},{"n":10,"sa":"לא יקנח ביד ימין:"},{"n":11,"sa":"לא יקנח בחרס משום כשפים ולא בעשבים יבשים שהמקנח בדבר שהאור שולט שיניו התחתונות נושרות ולא בצרור שקנח בו חבירו מפני שמביא את האדם לידי תחתוניות: הגה ועכשיו שבתי כסאות שלנו אינן בשדה נהגו לקנח (בחרס וכן נהגו לקנח) בדבר שהאור שולט בו ואינו מזיק ופוק חזי מאי עמא דבר. (חדושי אגודה פרק המוציא):"},{"n":12,"sa":"יפנה בצניעות בלילה כמו ביום:"},{"n":13,"sa":"לא ישתין מעומד מפני ניצוצות הניתזין על רגליו אם לא שיעמוד במקום גבוה או שישתין לתוך עפר תחוח (פירוש קרקע שאינה בתולה אלא כגון של ארץ חרושה):"},{"n":14,"sa":"יזהר שלא יאחוז באמה וישתין אם לא מעטרה ולמטה מפני שמוציא ש\"ז לבטלה אלא אם כן הוא נשוי ומדת חסידות ליזהר אפילו הנשוי:"},{"n":15,"sa":"אפי' מי שאינו נשוי מותר לסייע בבצים:"},{"n":16,"sa":"לא הותר לנשוי לאחוז באמה אלא להשתין אבל להתחכך לא:"},{"n":17,"sa":"המשהה נקביו עובר משום בל תשקצו:"}],"mb":[{"n":"א","t":"(א) ועכשיו וכו' - כי אין אנו מוחזקין ליראי שמים שמלאכים מלוין אותנו שנבקשם שימתינו עלינו עד שנצא:"},{"n":"ב","t":"(ב) עד שישב - וה\"ה שלא יקום כשהוא מגולה:"},{"n":"ג","t":"(ג) ולא ילכו - ואם מפחד יכול אחד להניח ידו על ראשו דרך החלון ובלבד שלא יראה פירועו וכדלקמן בס\"ח וליכנס שם להדיא אסור אפילו עם אשתו אך עם קטן שאין בו דעת מותר ליכנס [ארה\"ח]:"},{"n":"ד","t":"(ד) לא ידבר - ואם הוא לצורך גדול אפשר דמותר לדבר כ\"ז שאין נפנה עדיין אבל בעת שנפנה אף לצורך גדול אסור ואם א\"א לסגור הדלת ואיש אחר רוצה לכנוס ינחרו זה לזה ולא ידברו רק הנשים כשהולכות לבית הכסא הקבוע לרבים כמו בהכ\"ס שבשדה בימיהם או בחצר בהכנ\"ס במדינות אלו התקינו חכמים שיהיו מספרות זו עם זו כדי שישמע קולן מבחוץ ולא יכנוס איש לשם ויתיחד עמהן [סנהדרין י\"ט] ומשמע קצת שם דנכנסות ג\"כ בשתים בבהכ\"ס:"},{"n":"ה","t":"(ה) למשמש - אם אינו יכול לפנות ילך ד\"א וישב ויעמוד וישב עד שיפנה או יסיח דעתו מדברים אחרים. ולא יפנה בעמידה:"},{"n":"ו","t":"(ו) טפח - ולא יותר משום צניעות ומלפניו טפחיים דמתוך שהוא דוחק א\"ע לגדולים הוא בא לידי קטנים וצריך טפחיים משום קלוח מי רגלים הנתזין למרחוק והב\"ח כתב דנכון להחמיר שיהיה גם מלפניו רק טפח ולא הסכימו עמו הרבה מהאחרונים. ויזהר שלא ילכלך שם בגדיו וגופו ומנעליו:"},{"n":"ז","t":"(ז) מגולה - אבל בחצר בכל ענין שרי כ\"כ הב\"י והמ\"א אבל הט\"ז הסכים עם מהר\"י אבוהב דבחצר ג\"כ אסור באמצע החצר בין מזרח למערב דהלא מגולה הוא באותו מקום אם לא שמקרב עצמו לצד אחד מהכתלים וכ\"כ הדרישה וש\"א:"},{"n":"ח","t":"(ח) שאין בו מחיצות - אבל אם יש בו מחיצות ואפילו רק מחיצה אחת לצד מערב ישב בצד המחיצה בסמוך לה [דהיינו עכ\"פ בתוך ד' אמות] ואחוריו למערב כלפי המחיצה ונפנה שם וכן אם הכותל במזרח יושב בסמוך לה ואחוריו למזרח ויש מחמירין בזה מפני שפירועו שלפניו הוא לצד מערב והשכינה במערב ובמקום שאפשר טוב להחמיר. כתב הפמ\"ג דאין שיעור לגובה המחיצה רק כל שאין פירועו מגולה עי\"ז שרי:"}]},{"n":"ד","title":"דִּינֵי נְטִילַת יָדַיִם","seifim":[{"n":1,"sa":"ירחץ ידיו ויברך על נטילת ידים: הגה וי\"א גם אשר יצר ואפי' לא עשה צרכיו (וכן נהגו) (אבודרהם) מים הפסולים לנטילת ידים לסעודה לקמן סימן ק\"ס כשרים לנטילת ידים לתפלה מיהו יש מי שאומר דלא מברך עלייהו:"},{"n":2,"sa":"ידקדק לערות עליהם מים ג' פעמים להעביר רוח רעה ששורה עליהן:"},{"n":3,"sa":"לא יגע בידו קודם נטילה לפה ולא לחוטם ולא לאזנים ולא לעינים:"},{"n":4,"sa":"אפילו מי שנטל ידיו לא ימשמש בפי הטבעת תמיד מפני שמביאתו לידי תחתוניות ולא יגע במקום הקזה שמשמוש היד מזיק לחבורה:"},{"n":5,"sa":"לא יגע בגיגית שכר שמשמוש היד מפסיד השכר:"},{"n":6,"sa":"אין צריך רביעית לנטילת ידים לתפלה:"},{"n":7,"sa":"טוב להקפיד בנטילת ידים שחרית בכל הדברים המעכבים בנטילת ידים לסעודה (הגה מיהו אינו מעכב לא כלי ולא כח גברא ושאר דברים הפוסלים בנטילת הסעודה (מרדכי ריש פ' אלו דברים תשובת רשב\"א סימן קצ\"א):"},{"n":8,"sa":"נטילת ידים שחרית אין נוטלין ע\"ג קרקע אלא לתוך כלי:"},{"n":9,"sa":"מים של נט\"י שחרית אסור ליהנות מהם ולא ישפכם בבית ולא במקום שעוברים שם בני אדם:"},{"n":10,"sa":"נוטל כלי של מים ביד ימינו ונותנו ליד שמאלו כדי שיריק מים על ימינו תחלה:"},{"n":11,"sa":"לא יטול ממי שלא נטל ידיו שחרית:"},{"n":12,"sa":"אם שכשך ידיו לתוך כלי של מים עלתה לו נטילה לק\"ש ולתפלה אבל לא לרוח רעה שעליהם אם שכשך ידיו בשלש מימות מחולפים יש להסתפק אם עלתה לו להעביר רוח רעה שעליהם:"},{"n":13,"sa":"אם היה נעור כל הלילה יש להסתפק אם צריך ליטול ידיו שחרית להתפלל ולהעביר רוח רעה מידיו: הגה (ויטלם בלא ברכה) (הרא\"ש כלל ד' ורשב\"א סי' קצ\"א):"},{"n":14,"sa":"השכים קודם עמוד השחר ונטל ידיו יש להסתפק אם צריך ליטול ידיו פעם אחרת כשיאור היום להעביר רוח רעה השורה על הידים: הגה ויטלם בלא ברכ':"},{"n":15,"sa":"ישן ביום יש להסתפק אם צריך לערות מים עליהן ג' פעמים (ויטלם בלא ברכה):"},{"n":16,"sa":"דוד היה נזהר שלא לישן שיתין נשמין (פירוש ששים נשימות) כדי שלא יטעום טעם מיתה: הגה ובגמרא פ' הישן משמע דדוקא ביום היה נזהר: (דברי עצמו ועיין בב\"י):"},{"n":17,"sa":"יש נוהגין לרחוץ פיהם שחרית מפני הרירין שבתוך הפה:"},{"n":18,"sa":"אלו דברים צריך נטילה במים. הקם מהמטה והיוצא מבית הכסא. ומבית המרחץ. והנוטל צפורניו. והחולץ מנעליו. והנוגע ברגליו. והחופף ראשו וי\"א אף ההולך בין המתים. ומי שנגע במת. ומי שמפליא כליו. והמשמש מטתו. והנוגע בכנה. והנוגע בגופו בידו. ומי שעשה אחת מכל אלו ולא נטל אם ת\"ח הוא תלמודו משתכח. ואם אינו ת\"ח יוצא מדעתו:"},{"n":19,"sa":"המקיז דם מהכתפים ולא נטל ידיו מפחד שבעה ימים. המגלח ולא נטל ידיו מפחד ג' ימים. הנוטל צפרניו ולא נטל ידיו מפחד יום א' ואינו יודע ממה מפחד:"},{"n":20,"sa":"הרוחץ פניו ולא נגבם יפה פניו מתבקעו' או עול' בהן שחין ורפואתו לרחוץ הרבה במי סילקא:"},{"n":21,"sa":"צריך לזהר בתפלה או באכילה (וע\"ל סי' צ\"ב ס\"ז וסי' קס\"ד) שלא ליגע בשוק וירך ובמקומות המכוסים באדם לפי שיש שם מלמולי זיעה. מלמולי זיעה פ' זוהמא כעין שעורים קטנים) וכן שלא לחכך בראשו אבל מקומו' המגולי' בראשו ובפניו ומקו' המגולה שבזרועותיו אין להקפיד:"},{"n":22,"sa":"אם אין לו מים יקנח ידיו בצרור או בעפר או בכל מידי דמנקי ויברך על נקיות ידים ויועיל לתפלה אבל לא להעביר רוח רעה שעליהן:"},{"n":23,"sa":"לא תקנו נטילת ידים אלא לק\"ש ולתפלה אבל ברכות דשחרית יכול לברך קודם נטילה אא\"כ הוא ישן על מטתו ערום שאז אסור להזכיר את השם עד שינקה אותם:"}],"mb":[{"n":"א","t":"(א) ירחץ ידיו וכו' - יש ע\"ז שני טעמים הרא\"ש כתב לפי שידים של אדם עסקניות הן וא\"א שלא יגע בבשר המטונף בלילה לזה תקנו חז\"ל ברכה על הנטילה לק\"ש ולתפלה והרשב\"א כתב לפי שבשחר אחר השינה אנו נעשים כבריה חדשה דכתיב חדשים לבקרים רבה אמונתך צריכין אנו להודות לו יתברך שבראנו לכבודו לשרתו ולברך שמו ועל דבר זה תקנו בשחר כל אותן הברכות שאנו מברכין בכל בוקר לכן גם דבר זה תקנו בשחר להתקדש בקדושתו וליטול ידינו מן הכלי ככהן שמקדש ידיו מן הכיור קודם עבודתו. ולהלכה אנו תופסים כשני הטעמים לחומרא לענין נטילה וכדלקמן בזה הסימן. ואם לא בירך ענט\"י קודם התפלה שוב לא יברך אחר התפלה לכו\"ע [ח\"א]:"},{"n":"ב","t":"(ב) ויברך - ומיד אחר הנטילה יברך וא\"צ להמתין על הניגוב וגם הניגוב אין מעכב. ויש מחמירין שלא יברך עד אחר שינגב ידיו דס\"ל דאין רוח רעה סר מהידים עד אחר הניגוב וס\"ל דאסור לברך בידים שר\"ר שורה עליהם אבל דעת הפוסקים אין כן [ארה\"ח]. כתב בסדר היום שלא יגע במלבושיו עד שיטול ובגמרא לא משמע כן [מ\"א] איתא בברכות דף נ\"א אל תטול חלוקך שחרית מיד השמש ותלבש משום סכנת מזיקין אלא יטלהו בעצמו ממקום שהוא שם. ואפילו אותו השמש כבר נטל ידיו. אמרינן בגמרא רוחץ אדם פניו ידיו ורגליו בכל יום משום כבוד קונו. ובמדינותינו שאין אנו הולכים יחפים א\"צ לרחוץ רגליו שחרית [פמ\"ג]:"},{"n":"ג","t":"(ג) גם אשר יצר - הטעם משום דבבוקר נעשה כבריה חדשה וצריכין אנו להודות לו וניתקן ברכת אלקי נשמה ואשר יצר על יצירת הגוף ויש עוד טעמים אחרים עיין באחרונים וכתב הפמ\"ג דלפי הטעם דבריה חדשה אם היה ניעור כל הלילה דאז לא נעשה בריה חדשה בבוקר אין יכול לברך אשר יצר אם לא עשה צרכיו. יש אומרים דאם השתין בלילה יוכל לסמוך לענין ברכת אשר יצר על אשר יצר דשחרית וצ\"ע לדינא גם פעמים רבות יקרה שבבוקר משתוקק עוד הפעם להטלת מי רגלים ולא יוכל לחול עוד הברכת אשר יצר דבבוקר ע\"ז הטלה דלילה וכדלקמן בסי' ז' במ\"ב ס\"ק א'. וי\"ש יחמיר על עצמו ויטול ידיו וילבוש מכנסים או יחגור בשאר דבר להפסיק בין לבו לערוה ויברך אשר יצר. אך יראה בעת הברכה להרחיק מהעביט של המי רגלים ד' אמות אם הוא עומד בחדרו ואם לא היה העביט מיוחד לזה די בהטלת רביעית מים לתוך המי רגלים בכל פעם ופעם שמשתין:"},{"n":"ד","t":"(ד) ואפילו וכו' - והרוצה להסתלק מן הספק יזהר לעשות צרכיו תיכף אחר שעירה מים על ידיו ג\"פ וכשיצא מבהכ\"ס יטול ידיו פעם שניה ויברך אשר יצר ויצא ידי חובה לכו\"ע. וטוב יותר שלא יברך אפילו ברכת נט\"י עד לאחר נטילה שניה שנוטל אחר יציאתו מבהכ\"ס ובפרט אם היה צריך לנקביו בעת נטילה ראשונה שאז בודאי אינו רשאי לברך. והח\"א כתב דנכון להמתין מלברך ענט\"י עד לאחר שמנקה עצמו ורוצה להתפלל עי\"ש טעמו אח\"כ מצאתי בספר מעשה רב שכן היה נוהג הגר\"א ז\"ל ועיין בבה\"ל:"},{"n":"ה","t":"(ה) סימן ק\"ס - דהיינו מים שנשתנו מראיהן או נעשו בהם מלאכה או מלוחים או סרוחים שאין הכלב יכול לשתות מהם ומשו\"ה ראוים לתפלה דכאן לא צריך רק משום נקיות בעלמא:"},{"n":"ו","t":"(ו) דלא מברך - ר\"ל על נטילת ידים רק על נקיות ידים:"},{"n":"ז","t":"(ז) עלייהו - והאחרונים הכריעו דיוכל לברך על נטילת ידים ועיין לקמן בסעיף ז' ובמ\"ב ס\"ק ט\"ז:"},{"n":"ח","t":"(ח) ידקדק - כי חוץ מהטעמים הנזכרים בסק\"א שצריך ליטול ידיו לתפלה צריך ליטול גם משום רוח רעה השורה על הידים אך היכא דהנטילה הוא משום רוח רעה לבד לא היו מתקנים ע\"ז ברכה לכן אנו צריכים גם לטעמים הנ\"ל:"}]},{"n":"ה","title":"כַּוָּנַת הַבְּרָכוֹת וְהַתְּפִלָּה","seifim":[{"n":1,"sa":"כוונת הברכות. ובו סעיף אחד: יכוין בברכות פירוש המלות כשיזכיר השם יכוין פירוש קריאתו באדנות שהוא אדון הכל ויכוין בכתיבתו ביו\"ד ה\"א שהיה והוה ויהיה ובהזכירו אלהים יכוין שהוא תקיף בעל היכולת ובעל הכחות כולם:"}],"mb":[{"n":"א","t":"(א) פירוש המלות - כמו שאחז\"ל [ברכות מ\"ז] שלא יזרוק הברכה מפיו אלא יכוין בעת האמירה ויברך בנחת וז\"ל ס\"ח סי' מ\"ו כשהוא נוטל ידיו או שמברך על הפירות או על המצות השגורות בפי כל אדם יכוין לבו לשם בוראו אשר הפליא חסדו עמו ונתן לו הפירות או הלחם להנות מהם וציוהו על המצות ולא יעשה כאדם העושה דבר במנהג ומוציא דברים מפיו בלא הגיון הלב ועל דבר זה חרה אף ה' בעמו ושלח לנו ביד ישעיה ואמר יען כי ניגש העם הזה בפיו ובשפתיו כבדוני ולבו רחק ממני ועי\"ש עוד מה שהאריך בגודל העונש עבור זה:"},{"n":"ב","t":"(ב) קריאתו באדנות - כי השם הנכבד והנורא אסור לקרותו ככתבו כמשאחז\"ל ההוגה את השם באותיותיו אין לו חלק לעוה\"ב אלא צריך לקרותו כאלו היה כתוב שם אדני וגם בנקודת אדני דהיינו האלף בחטף פתח אבל לא בפתח לבד או בשב\"א לבד והד' בחולם והנון בקמץ וידגיש היו\"ד שתהא ניכרת יפה רק בכונה יכוין לשם הוייה. וטעם הנגינה הוא מלרע:"},{"n":"ג","t":"(ג) שהיה וכו' - ובביאור הגר\"א כתב דלפי עומק הדין א\"צ לכוין אלא פי' קריאתו דבכל מקום הולכין אחר הקריאה אף שיש בהכתיבה סודות גדולות לבד בקריאת שמע שם צריך לכוין ג\"כ שהיה וכו' עי\"ש. ובמקום שנכתב בא\"ד לכו\"ע אין צריך לכוין אלא שהוא אדון הכל. אם אחד מספר חסדי ה' שעשה לו ומתחלה מזכיר השם ורוצה לגמור דבריו מה שעשה לו ה' אסור להפסיקו בדברים שמא מתוך כך לא יגמור דבריו ונמצא שהזכיר ש\"ש בחנם אבל אם רוצה לקלל שום אדם והתחיל בשם מצוה להפסיקו שלא יגמור דבריו ולא יחטא [ס\"ח והובא בחידושי רע\"א]:"}]},{"n":"ו","title":"בִּרְכַּת אֲשֶׁר יָצַר וֵאלֹקַי נְשָׁמָה","seifim":[{"n":1,"sa":"כשיצא מבית הכסא יברך אשר יצר את האדם בחכמה שבריאת האדם היא בחכמה נפלאה וי\"מ על שם שהגוף דומה לנוד מלא רוח והוא מלא נקבים כדלקמן בסמוך וי\"מ בחכמה שהתקין מזונותיו של אדם הראשון ואח\"כ בראו וברא בו נקבים נקבים חלולים חלולים פירוש נקבים רבים כגון פה וחוטם ופי טבעת וגם ברא בו אברים רבים חלולים כמו לב וכרס ומעים. שאם יסתם אחד מהם כלומר שבנקבים יש נקב א' שהוא הפה כשהוא במעי אמו הוא סתום וכשיוצא לאויר העולם הוא נפתח ואם כשיוצא לאויר העולם היה נשאר סתום לא היה אפשר להתקיים אפי' שעה אחת והאברים החלולים אם היה נפתח אחד מהם לא היה אפשר להתקיים אפי' שעה אחת. ועוד יש לפרש שגבול יש לאדם שיכולין נקביו ליסתם ולא ימות וכיון שעבר אותו הגבול אי אפשר להתקיים אפילו שעה אחת וכיון שבכלל הנקבים הם פי הטבעת ופי האמה ובכלל האברים החלולים שאם יפתח אחד מהם אי אפשר להתקיים הם כרס ומעים שפיר הוי שבח זה מענין עשיית צרכיו ואפשר עוד שמאחר שאם יוצא לנקביו ביותר עד שאם עבר הגבול ימות בכלל שאם יפתח אחד מהם הוא. והוי שאם יפתח אחד מהם נמי מענין עשיית צרכיו ממש. רופא חולי כל בשר ע\"ש הנקבים שברא בו והוציא פסולת מאכלו כי אם יתעפש בבטן ימות והוצאתו הוא רפואה. ומפליא לעשות מפני שהאדם דומה לנוד מלא רוח ואם יעשה אדם בנוד נקב כחודה של מחט הרוח יוצא והאדם מלא נקבים ורוחו משתמרת בתוכו הרי זה פלא ועוד יש לפרש על שם שבורר טוב המאכל ודוחה הפסולת: הגה ועוד יש לפרש שמפליא לעשות במה ששומר רוח האדם בקרבו וקושר דבר רוחני בדבר גשמי והכל הוא ע\"י שהוא רופא כל בשר כי אז האדם בקו הבריאות ונשמתו משתמרת בקרבו (דברי עצמו):"},{"n":2,"sa":"יש נוהגין להמתין לברך על נטילת ידים עד בואם לבית הכנסת ומסדרים אותם עם שאר הברכות ובני ספרד לא נהגו כן: (ועכ\"פ לא יברך ב' פעמים ומי שמברכם בביתו לא יברך בבה\"כ וכן מי שמברכה בבה\"כ לא יברך בביתו (כל בו סי' ב') ומי שלומד קודם שיכנס לבה\"כ או מתפלל קודם יברכה בביתו ולא יברך בבה\"כ ואפי' בכהאי גונא יש נוהגין לסדרה עם שאר ברכות בב\"ה ואין מברכין בביתם): (מהרי\"ל הלכות תפלה):"},{"n":3,"sa":"ברכת אלהי נשמה אינה פותחת בברוך מפני שהיא ברכת ההודאה וברכת ההודאות אין פותחת בברוך כמו שמצינו בברכת הגשמים:"},{"n":4,"sa":"יש נוהגין שאחר שבירך א' ברכת השחר וענו אחריו אמן חוזר א' מהעונים אמן ומברך ועונין אחריו אמן וכסדר הזה עושין כל אותם שענו אמן תחלה ואין לערער עליהם ולומר שכבר יצאו באמן שענו תחלה מפני שהמברך אינו מכוין להוציא אחרים ואפילו אם היה המברך מכוין להוציא אחרים הם מכונים שלא לצאת בברכתו:"}],"mb":[{"n":"א","t":"(א) חלולים - פי' איברים חלולים ולא יאמר חללים דבחלל לא שייך בריאה:"},{"n":"ב","t":"(ב) שאם יסתם וכו' - כן היא גי' הרמב\"ם אבל גירסא שלנו ורש\"י ורי\"ף והרא\"ש אם יפתח קודם [הגר\"א]:"},{"n":"ג","t":"(ג) כלומר שבנקבים וכו' - משום דגירסתו היה א\"א להתקיים אפילו שעה אחת וקשה לו דאדם סותם פיו הרבה שעות ולזה קאמר כלומר וכו' אבל מנהגינו שלא לומר אפילו שעה אחת כמש\"כ הר\"מ וכן מוכח באגודה כ\"כ המ\"א וכן משמע בביאור הגר\"א ועיין ט\"ז:"},{"n":"ד","t":"(ד) אי אפשר - אי בצירי תחת האלף כי המלה נגזרת מן אין כ\"כ הבה\"ט והפמ\"ג ובשע\"ת מיישב הגירסא בחירק שג\"כ כונתו כמו אין כמו דכתיב אי כבוד שפירש\"י שם שכונתו כמו אין כבוד:"},{"n":"ה","t":"(ה) רופא (חולי) - ב\"ח ושל\"ה ומט\"מ כתבו שאין לומר חולי רק רופא כל בשר וט\"ז כתב דשני הגירסאות הן נכונות וחלילה למחוק אחת מהן עיי\"ש:"},{"n":"ו","t":"(ו) דבר רוחני - ובכוונת כתוב דהנשמה נהנית מרוחניות המאכל והגוף נהנה מגשמיות המאכל ומכח זה קשורים זה בזה ע\"י המאכל [מ\"א]:"},{"n":"ז","t":"(ז) להמתין - קבלה מר\"י חסיד היוצא מביתו לבהכ\"נ קודם שיתפלל יאמר פסוק שמע ישראל אבל יכוין שלא לצאת בזה המ\"ע דק\"ש אא\"כ ירא שיעבור זמן ק\"ש ועיין לקמן בסוף סימן מ\"ו מה שכתבנו במ\"ב שם:"},{"n":"ח","t":"(ח) לברך - ודוקא אם הולך מיד לבהכ\"נ אבל אם לומד אחר הנטילה וכ\"ש כשמפסיק בשיחה בטלה ואח\"ז הולך לבהכ\"נ ומברך שם ענט\"י לכו\"ע לא עביד שפיר דיש הפסק גדול בין נטילה לברכה וכדלקמיה ע\"כ אותם שאומרים תהלים קודם ענט\"י לא יפה הם עושים דהוי הפסק גדול. כתב הלבוש אותם שאומרים תהלים טוב יותר שיאמרו קודם התפלה ע\"ש הטעם:"}]},{"n":"ז","title":"דִּין הַנִּפְנֶה","seifim":[{"n":1,"sa":"כל היום כשעושה צרכיו בין קטנים בין גדולים מברך אשר יצר ולא על נטילת ידים אף אם רוצה ללמוד או להתפלל מיד: הגה היו ידיו מלוכלכות ששפשף בהן א\"ה אינו מברך על נטילת ידים: (סמ\"ג סי' כ\"ז מ\"ט):"},{"n":2,"sa":"הטיל מים ולא שפשף אע\"פ שצריך לברך אשר יצר אין צריך ליטול ידיו אלא משום נקיות או משום הכון:"},{"n":3,"sa":"הטיל מים והסיח דעתו מלהטיל מים ואח\"כ נמלך והטיל מים פעם אחרת צריך לברך ב\"פ אשר יצר:"},{"n":4,"sa":"אין שיעור להשתין מים כי אפילו לטפה אחת חייב לברך שאם יסתם הנקב מלהוציא הטפה ההיא היה קשה לו וחייב להודות:"}],"mb":[{"n":"א","t":"(א) מברך וכו' - ואפילו אם נמשך זמן גדול אחר עשיית הצרכים אפ\"ה חייב לברך. ואם לא בירך אשר יצר עד שרוצה להטיל מים שנית דעת הפמ\"ג דמקודם שיטיל יברך אשר יצר על ההטלה הראשונה אבל בש\"ת הסכים בשם כמה אחרונים דאם נזכר לאחר שהתחיל לו תאוה שוב לא יברך עי\"ש:"},{"n":"ב","t":"(ב) אשר יצר - כתב רש\"ל בתשובה סימן צ\"ז מי שאכל דבר שחייב ברכה אחרונה ושכח והטיל מים ונזכר קודם שבא לברך אשר יצר איזה מהם קודם והשיב דאשר יצר קודם דתדיר. מי ששותה סם המשלשל דיש בדעתו מתחלה לפנות הבני מעיים עד שתכלה הזוהמא מהם ע\"כ י\"א דלא יברך כ\"א אחר גמר ההוצאה וי\"א דיברך בכל פעם והמנהג כסברא אחרונה אך בשלשול חזק שמרגיש שמיד יצטרך לפנות שנית אסור לברך כדלקמן סימן צ\"ב שאפי' בד\"ת אסור [ש\"ת]:"},{"n":"ג","t":"(ג) להתפלל מיד - אף דקיי\"ל בסימן רל\"ג ס\"ב דלתפלת מנחה וכן לערבית אפילו אינו יודע להן שום לכלוך צריך ליטול ידיו וכ\"ש כשעשה צרכיו מ\"מ אינו מברך ענט\"י אלא בשחרית. ועיין בספר ארצות החיים שכתב דדעת רוב הפוסקים דאם עשה צרכיו לגדולים ואח\"כ רוצה להתפלל מברך ענט\"י. ומ\"מ לכתחלה אין לזוז מפסק השו\"ע ועיין בספר מעשה רב:"},{"n":"ד","t":"(ד) ששפשף בהן - הניצוצות של מי רגלים וה\"ה בגדולים שעשה צרכיו וקנח:"},{"n":"ה","t":"(ה) אלא משום וכו' - ואם אין לו במה ליטול אעפ\"כ צריך לברך אשר יצר. ואפילו אם שפשף משמע לעיל בסוף סימן ד' במ\"א סקכ\"ח דמהני לברכות אם מנקה ידיו בכל מידי דמנקי:"},{"n":"ו","t":"(ו) ב' פעמים - כדמצינו לענין תפלה שאם טעה ולא התפלל שחרית מתפלל מנחה שתים. אבל הרבה מהאחרונים חולקין על פסק זה וסוברין דשאני תפלה שהיא במקום קרבן ושייך בו תשלומין משא\"כ באשר יצר שהיא ברכת הודאה יוצא בהודאה אחת על הרבה פעמים כמי שאכל שתי פעמים והסיח דעתו בינתים שמברך בהמ\"ז אחת על שתיהן. ויש להקל בספק ברכות. ולכתחילה נכון ליזהר לברך תיכף אשר יצר אחר הטלת מים דשמא יצטרך עוד אח\"כ להטיל מים וה\"ה בגדולים:"}]},{"n":"ח","title":"דִּינֵי צִיצִית וּלְבִישָׁתָהּ","seifim":[{"n":1,"sa":"יתעטף בציצית ויברך מעומד:"},{"n":2,"sa":"סדר עטיפתו כדרך בני אדם שמתכסים בכסותן ועוסקים במלאכתם פעמים בכיסוי הראש פעמים בגלוי הראש ונכון שיכסה ראשו בטלית:"},{"n":3,"sa":"טליתות קטנים שלנו שאנו נוהגים ללבוש אף על פי שאין בהם עיטוף יוצאים בהם ידי חובת ציצית וטוב להניח אותו על ראשו רחבו לקומתו ולהתעטף בו ויעמוד כך מעוטף לפחות כדי הלוך ד\"א ואח\"כ ימשכנו מעל ראשו וילבישנו:"},{"n":4,"sa":"מחזיר שתי ציציות לפניו ושתים לאחוריו כדי שיהא מסובב במצות:"},{"n":5,"sa":"מברך להתעטף בציצית אם שנים או שלשה מתעטפים בטלית כאחת (פירוש בפעם אחת) כולם מברכים ואם רצו אחד מברך והאחרים יענו אמן:"},{"n":6,"sa":"על טלית קטן יכול לברך להתעטף אע\"פ שאינו מתעטף אלא לובשו. הגה וי\"א שמברכין עליו על מצות ציצית וכן נוהגין ואין לשנות: (כל בו סי' כ\"ב ונ\"י בה\"ק דף פ\"ו ט\"ב):"},{"n":7,"sa":"צריך להפריד חוטי הציצית זה מזה:"},{"n":8,"sa":"יכוין בהתעטפו שצונו הקב\"ה להתעטף בו כדי שנזכור כל מצותיו לעשותם:"},{"n":9,"sa":"קודם שיברך יעיין בחוטי הציצית אם הם כשרים כדי שלא יברך לבטלה:"},{"n":10,"sa":"אם לובש טלית קטן בעוד שאין ידיו נקיות ילבישנו בלא ברכה וכשיטול ידיו ימשמש בציצית ויברך עליו או כשילבש טלית אחר יברך עליו ויכוין לפטור גם את זה ואין צריך למשמש בציצית של ראשון:"},{"n":11,"sa":"עיקר מצות טלית קטן ללבשו על בגדיו כדי שתמיד יראהו ויזכור המצות:"},{"n":12,"sa":"אם יש לו כמה בגדים של ארבע כנפות כלם חייבים בציצית ואם לבשם כלם בלא הפסק והיה דעתו מתחלה על כלם לא יברך אלא ברכה אחת ואם מפסיק ביניהם צריך לברך על כל אחת ואחת וה\"ה אם לא היה בדעתו מתחלה על כלם הוי כמפסיק ביניהם: הגה וכן אם פשט הראשון קודם שלבש השני צריך לחזור ולברך (ת\"ה סי' מ\"ה):"},{"n":13,"sa":"הלובש טלית קטן ומברך עליו כשהולך לבהכ\"נ ומתעטף בטלית גדול צריך לברך עליו דהליכה מביתו לבהכ\"נ חשיבה הפסק ואם מתפלל בתוך ביתו אם היה דעתו מתחל' גם על טלית גדול ולא הפסיק בינתים בשיחה או בדברים אחרי' אינו צריך לחזור ולברך:"},{"n":14,"sa":"ואם פשט טליתו אפי' היה דעתו לחזור ולהתעטף בו מיד צריך לברך כשיחזור ויתעטף בו: הגה וי\"א שאין מברכין אם היה דעתו לחזור ולהתעטף בו [אגור סימן ל\"ה] וי\"א דוקא כשנשאר עליו טלית קטן והכי נוהגין [שם] [עיין לקמן סימן כ\"ה סעיף י\"ב]:"},{"n":15,"sa":"אם נפלה טליתו שלא במתכוין וחוזר ומתעטף צריך לברך והוא שנפלה כולה אבל אם לא נפלה כולה אע\"פ שנפלה רובו א\"צ לברך:"},{"n":16,"sa":"הלן בטליתו בלילה צריך לברך עליו בבקר אף אם לא פשטו וטוב למשמש בו בשעת ברכה: וכן יעשה מי שלובש טליתו קודם שיאור היום: [הגמ\"יי בשם ספר התרומה וסמ\"ג וסמ\"ק והמרדכי בהלכו' תפילין]:"},{"n":17,"sa":"נתכסה בבגד שהוא חייב בציצית ולא הטיל בו ציצית ביטל מצות ציצית:"}],"mb":[{"n":"א","t":"(א) יתעטף בציצית – מיד אחר נטילת ידיים, כדי שלא ילך ארבע אמות בלא ציצית."},{"n":"ב","t":"(ב) מעומד – רוצה לומר, העטיפה והברכה שתיהן בעמידה. העטיפה, משום דכתיב \"לכם\", וילפינן גזרה שווה מעומר דכתיב גם כן \"לכם\", ובעומר כתיב: \"מהחל חרמש בקמה\", ודרשינן \"בקומה\". והברכה, משום דכל ברכת המצוות צריך להיות בעמידה. והוא רק לכתחילה, דבדיעבד יצא בשתיהן בכל גווני. והסכימו רוב האחרונים דלכתחילה צריך להיות הברכה קודם העטיפה, דהיינו בשעה שהוא אוחזו בידו ורוצה להתעטף בו, דזהו עובר לעשייתן ממש. ולא יקדים בשעה שעדיין הטלית מקופלת, דזהו עובר דעובר."},{"n":"ג","t":"(ג) בגילוי הראש – דאף על גב דמברכינן \"להתעטף\", כיסוי הגוף לחודיה הוי עיטוף, והוא עיקר העיטוף. ועוברי דרכים, שמניחין הטלית כשהוא מקופל ומשלשלים סביב צווארם על כתפיהן, אין יוצאין ידי חובת ציצית בזה, דבכהאי גוונא – לכולי עלמא לאו עיטוף הוא."},{"n":"ד","t":"(ד) בטלית – שכיסוי זה מכניע לב האדם ומביאו לידי יראת שמים. ועיין בט\"ז, שדעתו דנכון שלא יסיר הכובע הקטן שעל ראשו בעת התפילה, אף שהוא מכסה ראשו בהטלית גם כן. וכתב הב\"ח דצריך שיהא הטלית על ראשו מתחילת התפלה עד סופה. ועל כל פנים יעמוד כך מעוטף לפחות כדי הילוך ארבע אמות. כתוב בכוונות האר\"י ז\"ל: היה מכסה הטלית על התפילין של ראש. ועיין סוף סימן כ\"ז דעל כל פנים לא יכסה לגמרי. בשעת עטיפה מכסה ראשו בהטלית עד שיגיע עד פיו, ומשליך כל הארבע ציציות לצד שמאל כדי הילוך ארבע אמות. ואחר כך יסיר העטיפה, עד שהשל ראש יהיה נראה קצת, וכנ\"ל. ויעמיד כל אחת מהציצית על מקומה, וכדאיתא בסעיף ד'. וזהו העטיפה שיוצאין בה לכולי עלמא. ולא כמו שנוהגין איזה אנשים, שמושכין הטלית על עצמן עד שמגיע הראש לחצי אורך הטלית ומתעטפין בו, דזהו איננו נקרא עטיפה, עיין במועד קטן כד א. משמע בגמרא שבחור לא היה מכסה ראשו בטלית, אפילו הוא תלמיד חכם."},{"n":"ה","t":"(ה) טליתות קטנים – והוא שיש בהם שיעור שהקטן בן תשע שנים יתכסה בו ראשו ורובו, וגדול בן שלוש עשרה שנים על כל פנים לא יתבייש לצאת בו באקראי ברחוב, וכדלקמן בסימן ט\"ז, עיין שם במשנה ברורה."},{"n":"ו","t":"(ו) יוצאין בהם – דהאידנא כל כסות שלנו דרך כיסוי הם, ועיטוף לא רמיזא באורייתא."},{"n":"ז","t":"(ז) מעוטף – כדי לצאת נמי דעת הסוברים דבעינן דווקא עיטוף. ונראה דהנוהגין שלא לברך כלל על הטלית קטן, רק פוטרין אותו בברכת הטלית גדול, אין צריך כלל להתעטף בו. ועיין במגן אברהם ובביאור הגר\"א.[1]"},{"n":"ח","t":"(ח) ואחר כך – דעיקר הקפידא בעת לבישה."}]},{"n":"ט","title":"בְּאֵיזֶה בְּגָדִים חַיָּב בְּצִיצִית","seifim":[{"n":1,"sa":"אין חייב בציצית מן התורה אלא בגד פשתים או של צמר רחלים אבל בגדי שאר מינים אין חייבים בציצית אלא מדרבנן [וי\"א דכולהו חייבים מדאורייתא והכי הלכתא] [תוספות דף ל\"ט והרא\"ש סמ\"ג ומרדכי]:"},{"n":2,"sa":"ציצית של פשתים או של צמר ורחלים פוטרים בכל מיני בגדים חוץ משל פשתים לצמר או של צמר לפשתים בזמן הזה דליכא תכלת מפני שהם כלאים: הגה ויש אומרים שלא לעשות ציצית של פשתים כלל אפי' בשאר מינים והכי נהוג [סמ\"ק סימן ל\"א]:"},{"n":3,"sa":"ציצית של שאר מינים אין פוטרים אלא במינם כגון משי לבגד משי וצמר גפן לצמר גפן אבל שלא במינם אין פוטרין:"},{"n":4,"sa":"אם הטיל בטלית של שאר מינים קצת ציצי' ממינו וקצת מצמר או פשתים יש להסתפק בו:"},{"n":5,"sa":"י\"א שצריך לעשו' הציצי' מצבע הטלית והמדקדקים נוהגים כן: הגה והאשכנזים אין נוהגים לעשות הציציות רק לבנים אף בבגדים צבועים ואין לשנות [ת\"ה סימן מ\"ו]:"},{"n":6,"sa":"י\"א שאין לעשות טלית של פשתן אף על פי שאין הלכה כן ירא שמים יצא את כולם ועושה טלית של צמר רחלים שהוא חייב בציצית מן התורה בלי פקפוק: הגה ומיהו אם אי אפשר רק בטלית של פשתן מוטב שיעשה טלית של פשתן וציצית של פשתן משיתבטל מצות ציצית: [תשו' הרא\"ש כלל ב']:"}],"mb":[{"n":"א","t":"(א) אלא וכו' - כדתני דבי ר' ישמעאל דילפינן מנגעים דפרט ביה הכתוב צמר ופשתים אף כל מקום דכתיב ביה בגד הכונה מצמר ופשתים:"},{"n":"ב","t":"(ב) רחלים - או אילים זכרים אבל שאר כל המינים כגון צמר גמלים ונוצה של עזים והשירים וצמר ארנבים וכן קנבוס וכל כה\"ג אינן בכלל צמר ופשתים ואינם חייבים בציצית רק מדרבנן וצמר רחל בת עז כתב ב\"י דצמרה ג\"כ לא חשיב צמר ולא הוי אלא כשאר מינים וממילא ה\"ה דבכל אלו אם עשה מהן ציצית כ\"א מהן אינו פוטר אלא במינו. צמר רחלים או פשתן שטרפן בשאר מינין אזלינן בתר רובא אם הרוב הוא מצמר ופשתים חייב מן התורה וא\"ל מדרבנן. ודוקא אם טרפן וטוון ועשה מהן בגד אבל אם השתי מצמר או מפשתים והערב משאר מינין או איפכא אין חייב לדעה זו רק מדרבנן אפילו אם רובו מצמר ופשתים דשתי או ערב לחוד לא חשיב בגד. ולענין איזה ציצית לעשות בו עיין לקמן בס\"ק י\"ג ועיין בביאור הלכה:"},{"n":"ג","t":"(ג) אלא מדרבנן - אף דצריך לברך על מצוה שהיא מדרבנן ג\"כ מ\"מ נ\"מ לענין כמה דברים. א'. דיותר ראוי לעשות בגד שהוא יוצא בו מן התורה. ב'. אם נתערב לו ציצית טוויין לשמן בשלא לשמן ואין לו ציצית אחרים או שיש לו ספק על הבגד אם הוא חייב בציצית דאם הוא מדרבנן ספיקא דרבנן לקולא. ג'. אם הוא יושב בצבור ונפסק אחד מציציותיו בחול דאם הוא מדרבנן י\"ל כבוד הבריות דוחה דרבנן ואינו מחוייב תיכף לפשוט טליתו עיין בסי' י\"ג ועוד נ\"מ הרבה עיין בפמ\"ג:"},{"n":"ד","t":"(ד) וי\"א דכולהו וכו' - פוסקים כרבא דרבא רמי כתיב על ציצית הכנף משמע מין כנף פי' אפילו אינו של צמר ופשתים מ\"מ יהיו הציצית ממין הבגד וכתיב לא תלבש שעטנז צמר ופשתים יחדיו גדילים תעשה לך מהם הא כיצד צמר ופשתים פוטרין בין במינן ובין שלא במינן שאר מינין במינן פוטרין שלא במינן אין פוטרין ומכריע רמ\"א כדעה זו שכן סבירא להו לרוב האחרונים כרבא לדרוש מין כנף וש\"מ דכל מיני בגד חייב מן התורה בציצית ויהיה ממין הבגד:"},{"n":"ה","t":"(ה) והכי הלכתא - וי\"ש יחמיר על עצמו לחוש לדעה הראשונה ויעשה טלית של צמר כדי שיתחייב בציצית מן התורה לכו\"ע. ונכון שיעשה בין הט\"ג ובין הט\"ק של צמר:"},{"n":"ו","t":"(ו) של צמר וכו' - והב\"ח כתב כיון דיש פוסקים המחמירין בזה שלא לעשות אפילו ציצית של צמר לשאר מינין כיון שאינו מינו כמבואר בב\"י ע\"כ לא יברך רק על טלית צמר וציצית צמר והעולם נוהגין לעשות ציצית של צמר לשאר מינין ובספר א\"ר ג\"כ כתב שיש להקל בזה וכן משמע בספר מעשה רב:"},{"n":"ז","t":"(ז) בזמן הזה - פי' דבזמן שהיה תכלת שהיה צריך להטיל ד' חוטין שני חוטי לבן ושני חוטי תכלת (הוא צמר צבוע בדם חלזון) והיה מתקיים עי\"ז המצות ציצית כראוי התירה לנו התורה להטיל השנים של לבן בין מצמר או מפשתים בין בבגד צמר או בבגד פשתים ולהי\"א שזכר רמ\"א בס\"א דכל מיני בגדים חייבין מדאורייתא אפילו בהם היה אז מותר לנו מן התורה ציצית של צמר ופשתים יחדיו אבל עכשיו דאין לנו תכלת נמצא דאין אנו מקיימין המצוה בשלמותה לא שרי לן כלאים:"},{"n":"ח","t":"(ח) אפילו בשאר מינים - הטעם דיש צמר שנראה כעין משי ויבואו להטיל בו ציצית של פשתן שיסברו שהוא משי ויהיה כלאים. ולפ\"ז בשאר מינים שאינן משי יש להתיר ויש עוד טעמים אחרים עיין בב\"י וב\"ח וט\"ז ולדבריהם יש להחמיר גם בשאר מינים ובשעת הדחק יש לסמוך על המקילין כן כתב בא\"ר. ועיין בספר מעשה רב שהגר\"א היה ג\"כ מן המקילין בזה:"}]},{"n":"י","title":"דִּינֵי הֲטָלַת צִיצִית","seifim":[{"n":1,"sa":"טלית שאין לה ד' כנפו' פטורה יש לה יותר מארבע חייבת ועושה לה ארבע ציציות בארבע כנפו' המרוחקות זו מזו יותר:"},{"n":2,"sa":"יש לה ארבע וחתך א' באלכסון ועשהו שנים הרי נעשית בעלת ה' וחייבת:"},{"n":3,"sa":"כפל קרנות טליתו וקשרם או תפרם ודומה כאילו קיצען ואין לה כנפות אעפ\"כ לא נפטרה:"},{"n":4,"sa":"טלית של בגד וכנפיה של עור חייבת היא של עור וכנפיה של בגד פטורה:"},{"n":5,"sa":"היו לה ג' כנפו' ועשה בהם ג' ציציות ושוב עשה לה כנף ד' ועשה גם בו ציצי' פסולה משום תעשה ולא מן העשוי:"},{"n":6,"sa":"אין כופלין את הטלית ומטילים ציצי' על כנפיה כמו שהיא כפולה [הגה אבל צריך להטיל בד' כנפיה הפשוטים] [בית יוסף] אא\"כ תפרה כולה ואפי' מרוח אחת: [הגה וי\"א דחייבין אפי' בלא תפיר' וטוב לעשו' לה ציצית אבל לא לברך עליה [הרי\"ף והרא\"ש והטור]: הטיל ציצית על ציצית אם נתכוין לבטל הראשונה חותך הראשונה וכשרה ואם נתכוין להוסיף אע\"פ שחתך אחת משתיהן פסולה: [הגה ויש מכשירים בכל ענין וכן עיקר] [טור בשם הרא\"ש ורבי' ירוחם ני\"ח ח\"ג] וקודם שחתך מראשונה פסול בכל ענין [ב\"י]:"},{"n":7,"sa":"מלבושים שהם פתוחים מן הצדדין למטה ויש להם ד' כנפות לצד מטה ולמעלה הם סתומים אם רובו סתום פטור ואם רובו פתוח חייב ואם חציו סתום וחציו פתוח מטילין אותו לחומרא וחייב בציצית ואין יוצאין בו בשבת:"},{"n":8,"sa":"קאפ\"ה שהיא פתוחה בענין שיש לה ד' כנפות אם יקבעו בה אשטרינג\"ה לעשותה כסתומה כדי לפוטרה מציצית אינו מועיל תיקון זה אם לא תהיה קבוע מחצי ארכה למטה לכל הפחות וגם שתהיה קבוע למטה מהחגור למען יהיה הרוב הסתום רוב הנראה לעינים דאל\"כ יאסר משום מראית העין:"},{"n":9,"sa":"הכנפים צריך שיהיו מרובעות ולא שיהיו עגולות:"},{"n":10,"sa":"מצנפת פטורה אפי' של ארצות המערב שב' ראשיה מושלכים על כתפיהם וגופם ואע\"פ שמתכסה בה ראשו ורובו פטור כיון שעיקרה לכסות הראש דכסותך אמר רחמנא ולא כסות הראש:"},{"n":11,"sa":"סודר שנותנין על הצואר במלכות א\"י שנקרא בערבי שי\"ד וכן ביק\"א שהיו נותנין בספרד על כתפיהם פטורים:"},{"n":12,"sa":"מלבושים שבמצרים הנקראים גוח\"ש וכן מינטי\"ני ודולאפאני\"ש וקפטאני\"ש ופידוני\"ש שבתורגמה אע\"פ שיש להם ד' כנפים פטורים: (הגה וה\"ה מלבושים של גלילות בני אשכנז וספרד הואיל ואין כנפיהם עשוין שיהיו ב' לפניהם וב' לאחריהם מכוונים זו כנגד זו (פטורים) (בית יוסף לפי סברת מהרי\"ק:"}],"mb":[{"n":"א","t":"(א) שאין לה וכו' - בין בתחילת עשייתו ובין שחתך אח\"כ כנף אחד ועשהו עגול:"},{"n":"ב","t":"(ב) פטורה - מבואר בקרא דכתיב על ארבע כנפות כסותך ודרשינן בספרי ארבע ולא שלש ויותר מארבע מרבינן מאשר תכסה ואיפכא לא נוכל לומר שבכלל ה' ארבע ואין בכלל ג' ארבע ולאו דוקא בעלת ה' ה\"ה בעלת ו' וז':"},{"n":"ג","t":"(ג) חייבת - ויש פוטרין לכן אין לעשות בת ה' לכתחילה וכתב הפמ\"ג דלדעת הפוטרין אותן טליתות קטנים שלנו שיש בית הצואר מ\"מ רוב סתום ומיהו אם אירע שרוב פתוח יעשה בקאלנע\"ר שעושים החייטים קצת עגול:"},{"n":"ד","t":"(ד) בארבע - ואם עשה ה' עובר משום בל תוסיף ואם חתך אחת מהם כשרה אך שישארו הד' כנפות המרוחקות בציצית וכדלקמי':"},{"n":"ה","t":"(ה) המרוחקות זו מזו יותר - דמסתבר שיש לעשות באותם שהם ניכרים ביותר מן השאר וי\"א דהוא מדאורייתא ויש להחמיר אם אפשר אבל אם כבר נעשה בכנף הקרוב וא\"א לתקן כגון שהגיע זמן תפלה יכול לסמוך על המקילין ולברך:"},{"n":"ו","t":"(ו) אחת באלכסון - ה\"ה אם חתך ב' כנפות באלכסון נעשית בעלת ו':"},{"n":"ז","t":"(ז) בעלת ה' - וכן אם היה לה תחלה ג' וחתך כנף אחת לשנים נעשית בעלת ד' וחייבת בציצית וצריך שתהיה החתיכה גדולה וניכרת. ועיין בפמ\"ג שכתב דדוקא אם חתך מקצת מהבגד עד שעי\"ז נראה אותו המקום כשני קרנים אבל אם לא חתך כלום רק פגימה בסכין קרע בהקרן עד שנחלק אותו המקום לשנים לא נעשית עי\"ז בת ד' עד שיהא רוב פתוח וכדלקמן בס\"ז:"},{"n":"ח","t":"(ח) לא נפטרה - דאי לא מיבעי ליה הכנפים לפסוק ולישדייה אלא ודאי דסופו להתיר את התפירה הלכך נחשב כאלו כבר התיר התפירות וחייבת בציצית. ומטעם זה יוכל להטיל עתה הציצית בכפל אף למטה מקשר אגודל אם כשיתפשט יהיה למעלה מקשר אגודל. וכ\"ז בשכפלו ותפרו בעיגול אבל אם כפל ותפר בריבוע כיון שגם עתה יש כנף דעת הלבוש והמ\"א דרשאי להטיל שם הציצית בכפל אע\"פ שהוא יותר מג' אצבעות משפת הקרן כיון דתפרה שרי וכמו בס\"ו בכפל הטלית דמהני התפירה ורבים חולקין ע\"ז וס\"ל דגם בזה לא מהני התפירה ושאני ההיא דס\"ו דמיירי שכפלה כולה וכן דרך מלבוש משא\"כ בזה שלא כפל רק מקצת הבגד:"}]},{"n":"יא","title":"דִּינֵי חוּטֵי הַצִּיצִית","seifim":[{"n":1,"sa":"החוטין צריך שיהיו טווין לשמן: (הגה ויש מחמירין אפי' לנפצן לשמן והמנהג להקל בנפוץ) (מרדכי ואגודה סי' כ\"ג) שיאמר בתחלת הטווי שהוא עושה כן לשם ציצית או שיאמר לאשה טווי לי ציצית לטלית ואם לא היו טווין לשמן פסולים:"},{"n":2,"sa":"טוואן עכו\"ם וישראל עומד על גבו ואומר שיעשה לשמה להרמב\"ם פסול להרא\"ש כשר: הגה ונוהגין שיסייע הישראל מעט וכדאיתא לקמן סימן ל\"ב סעיף ט' ובי\"ד סימן רע\"א גבי תפילין וספר תורה: וצריכין שזירה ושיהיו שזורין לשמן:"},{"n":3,"sa":"אם נתפרקו משזירתן ונעשו י\"ו כשרים והוא שישתייר בשזור כדי עניבה: [הגה ולכתחילה טוב לקשור החוטין למטה כדלקמן בסעיף י\"ד בסימן זה: [ב\"י בשם הרוקח]:"},{"n":4,"sa":"אורך החטים השמנה אין פחות מארבע גודלים וי\"א י\"ב גודלים וכן נוהגין ולמעלה אין להם שיעור: [הגה ואם עשאו ארוך יותר מדאי יכול לקצרו ואין בזה משום תעשה ולא מן העשוי] [מרדכי בה\"ק] א' מהחוטים יהיה יותר ארוך כדי שיכרך בו הגדיל היינו החלק מהציצית שאינו ארוג: הגה ושיעור הנזכר יהיה בציצית לאחר שנקשר מלבד מה שמונח על קרן הבגד: (סבר' ב\"י):"},{"n":5,"sa":"אין עושין הציציות מהצמר הנאחז בקוצים כשהצאן רובצים ביניהם ולא מהנימין הנתלשים מהבהמה ולא משיורי שתי שהאורג משייר בסוף הבגד והטעם משום ביזוי מצוה:"},{"n":6,"sa":"אם עשאם מצמר גזול פסולים דכתיב ועשו להם משלה': הגה ודוקא שגזל החוטין אבל אם גזל צמר ועשאן חוטים כשרים מיהו לכתחלה אסור לעשותן [ב\"י בשם נימוקי יוסף בהלכות ציצית] [ולענין ברכה עיין לקמן ריש סי' תרמ\"ט]: ע' מ\"ש ר\"ס ט\"ו:"},{"n":7,"sa":"חוטים שאולין הלואה היא דלא הדרי בעינייהו וכדידיה דמי:"},{"n":8,"sa":"המשתחוה לבהמה צמרה פסול לציצית המשתחוה לפשתן נטוע כשר לציצית שהרי נשתנ':"},{"n":9,"sa":"יעשה נקב באורך הטלית לא למעלה מג' אצבעות [היינו גודלין] (כל בו סימן כ\"ב ומיימוני והגה' סמ\"ק' סי' ל\"א) שאינו נקרא כנף ולא למטה מכשיעור שיש מקשר גודל עד סוף הציפורן משום שנאמר על הכנף ואם היה למטה ממלא קשר גודל היה תחת הכנף: הגה ומודדין זה ביושר ולא באלכסון מן הקרן (ב\"י):"},{"n":10,"sa":"אם היה רחוק מהכנף מלא קשר גודל ונתקו מחוטי הערב עד שלא נשאר בו כשיעור כשר כיון שהיו בו כשיעור בשעה שהטיל בו ציצית זה: הגה ונוהגין לעשות אימרא סביב הנקב שלא ינתק שם ויהיה פחות מכשיעור וכן עושין אימרא בשפת הבגד למטה מהאי טעמא (ב\"י בשם סמ\"ק וכל בו) י\"א שבתוך רוחב הבגד אין לו שיעור וי\"א שדין רוחב הבגד כדין האורך ונראין דבריהם:"},{"n":11,"sa":"אם הגדיל שקורין אוריליי\"ו הוא רחב לא יטיל בו הציציות ואם הטיל בו פסול דעל כנפי בגדיהם כתיב וזה אינו נחשב מהבגד אבל עולה הוא לשיעור מלא קשר גודל ולהרחקת ג' אצבעות כיון שהנקב בתוך הבגד: הגה וטוב שימדוד שיעור קשר גודל בלא הגדיל ויהיה תוך ג' אצבעות עם הגדיל (ב\"י בשם רש\"י ורשב\"א):"},{"n":12,"sa":"מנין חוטי הציציות בכל כנף ארבעה כפולים שהם שמונה ואם הוסיף פסול יחתוך ראשי החוטין הארבעה ויתחבם בכנף ויכפלם ואז יהיו ח':"},{"n":13,"sa":"יזהר לחתוך ראשי החוטין לעשותם ח' קודם שיכרך שאם כרך אפי' חוליא אחד (פי' החלק מהציצית שבין קשר לקשר) וקשר אפי' קשר אחד ואח\"כ חתכן פסול משום תעשה ולא מן העשוי שהרי בפיסול עשאם:"},{"n":14,"sa":"יקח ד' חוטים מצד זה וד' מצד זה ויקשור שני פעמים זה על גב זה ואח\"כ יכרוך חוט הארוך סביב השבעה קצת כריכות וקושר שני פעמים זה על גב זה וחוזר וכורך וכן יעשה עד שישלים לחמשה קשרים כפולים וארבעה אוירים ביניהם מלאים כריכות אין שיעור לכריכות רק שיהי' כל הכרוך והקשרים רוחב ארבעה גודלים והענף שמנה גודלים: (הגה ואם האריך הציצית יראה ששלישיתו יהיה גדיל וב' חלקים ענף) (רמב\"ם פ\"א) נוהגים לכרוך באויר ראשון ז' כריכות ובשני ט' ובשלישי י\"א וברביעי י\"ג שעולים כלם ארבעים כמנין ה' אחד שעולים ל\"ט ועם השם הם ארבעים נהגו לעשות בסוף כל חוט קשר כדי שיעמוד בשזירתו:"},{"n":15,"sa":"י\"א שצריך לדקדק שיתלה הציצית לאורך הטלית דבעינן שתהא נוטפות על הקרן (פירוש תלוי על הקרן) ואם היה ברחבו לא היה נוטף שהרי כלפי קרקע היה תלוי. י\"א שאין לתת שום בגד בנקבי הטלית שמכניסים בהם הציציות ויש מתירין וכן נהגו:"}],"mb":[{"n":"א","t":"(א) החוטין - לשון הרמב\"ם המוצא חוטי ציצית בשוק אפילו פסוקים ושזורים פסולים דטרח איניש לעשות חוטין כעין ציצית וא\"כ שמא לא נעשה לשם ציצית. והמ\"מ חולק וגם בכ\"מ כתב דהרמב\"ם בתשובה חזר בו אח\"כ עכ\"ל המ\"א והגר\"א בביאוריו בסימן ש\"א כתב דהדין הוא עם הרמב\"ם כמו שכתב בראשונה עי\"ש:"},{"n":"ב","t":"(ב) טוויין לשמן - והוא ד\"ת דכתיב גדילים תעשה לך לשם חובך:"},{"n":"ג","t":"(ג) להקל בניפוץ - דמה דכתיב תעשה לך היינו מטוייה ואילך שאז היא עיקר עשיית הגדילים ועיין בפרישה בשם מהר\"ל מפראג שמסכים דלכתחילה יש להחמיר לנפץ לשמה:"},{"n":"ד","t":"(ד) שיאמר - בפירוש לא במחשבה בעלמא ואפילו בדיעבד צ\"ע אי מהני מחשבה ועיין בסימן ל\"ב ס\"ט וי\"ט ובחידושי רע\"א שם:"},{"n":"ה","t":"(ה) בתחילת - ודי בזה אפילו ליומא אוחרא דסתמא תו לשמה קאי דכל העושה ע\"ד ראשונה עושה אם לא כשאמר אח\"כ בפירוש שהוא עושה שלא לשמה:"},{"n":"ו","t":"(ו) הטווי - ואם טוה מעט ואח\"כ אמר לא מהני למה שנטווה כבר דספוקי מספקא לן אי אמרינן הוכיח סופו על תחילתו. ואם בתחלה ג\"כ חשב שיהיה לשמה אך שלא אמר בפירוש נ\"ל דיש לצדד להקל בזה דס\"ס הוא:"},{"n":"ז","t":"(ז) שיאמר לאשה - ר\"ל בתחלת הטוייה לבד. וה\"ה אם האשה בעצמה אומרת שהיא טווה לשם ציצית דמהני וגם נאמנת על כך שאמרה משא\"כ בעו\"ג וחש\"ו שאינם נאמנים. מומר לתיאבון שאין מטריח לעשות ציצית בבגדו מותר לטוות ומהימן כשאמר שטווה לשמה וכ\"ש אם הוא עובר רק על שאר עבירות לתיאבון אבל מומר להכעיס אפיקורס הוא לכל התורה כולה ובודאי אדעתא דנפשיה עביד לכו\"ע:"},{"n":"ח","t":"(ח) עו\"ג - וטווית חש\"ו אם מהני כשישראל גדול עומד על גבם ומלמדם לעשות לשמה עיין בסי' ת\"ס בב\"י שיש פלוגתא בזה ועיין בבה\"ל שביארנו הסכמת אחרונים בזה:"}]},{"n":"יב","title":"דִּין צִיצִית שֶׁנִּפְסְקָה","seifim":[{"n":1,"sa":"אם נפסקו כל חוטי הכנף ונשתייר בהם כדי עניבת כל החוטים הפסוקים ביחד כשר ואם לא נשאר כדי עניבה אפילו בחוט אחד שנפסק כולו פסול הלכך כיון שכל אחד כפול לשנים אם נפסקו שני ראשים פסול שמא נפסק חוט אחד ולפי מה שאנו נוהגים לדקדק בעת עשיית הציצית לתת סימן בד' ראשים בענין שלעולם הד' ראשים הם מצד אחד של הקשר והד' ראשים מצד האח' אם נפסקו שני ראשים מצד אחד כשר דודאי שני חוטין הם והרי נשתייר מכל אחד הראש השני שהוא יותר מכדי עניבה ולרבינו תם לא מכשירים אלא בנשתיירו ב' חוטין שלמים דהיינו ארבע ראשים שכל א' מהראשים ארוך י\"ב גודלים אז מכשירים כשנתפסקו השני חוטין אחרים אם נשתייר בהם כדי עניבה אבל אם נפסקו ג' חוטין אע\"פ שנשתייר בהם כדי עניבה פסולים ומפני כך כשנחתכו ג' ראשים אם לא דקדק בעת עשיית הציצית שיהיו ניכרים הד' ראשים שמצד אחד של הקשר חיישינן שמא כל ראש הוא מחוט א' ונמצא שאין כאן אלא חוט א' שלם הלכך מספיקא פסול הגה וכל שכן אם דקדק שיהיו ניכרין הד' ראשים שבצד אחד ונפסקו ג' ראשים בצד אח' דפסול דאז ודאי נפסקו ג' חוטין ואם נפסקו בב' צדדין נמי פסול שמא שלשה חוטין הם (ב\"י בשם בן חביב) אבל אם לא נחתכו אלא ב' ראשים מכשרינן בכדי עניבה והלכה כסברא ראשונה מיהו היכא דאפשר טוב לחוש לסברת רבינו תם: הגה ונוהגין כר\"ת (אגודה סימן ט\"ו) :"},{"n":2,"sa":"היכא דצריך כדי עניבה ומתוך שהחוטים עבים אינו יכול לענבם ואלו היו דקים היה בהם כדי עניבה כשר: הגה ומשערין בחוטין בינונים (דברי עצמו):"},{"n":3,"sa":"כדי עניבה לרש\"י מן הענף ולר\"י אפי' נחתך כל הענף ולא נשאר כדי עניבה אלא מן הגדיל כשר ומנהג העולם כרש\"י והיכא דלא אפשר יש לסמוך על ר\"י:"}],"mb":[{"n":"א","t":"(א) ונשתייר בהם - פי' בכל אחד מן החוט נשאר לעשות עניבה שקורין שליי\"ף לכל החוטין הפסוקים ביחד. ואם לא נפסקו כולן די אם נשאר לעשות עניבה על הפסוקים בלבד ולא על כל החוטין:"},{"n":"ב","t":"(ב) כשר - ואם התיר את הציצית אסור ליתנם בטלית אחר דהוי כלכתחלה ואפילו לא נפסק רק חוט אחד ואין בארכו י\"ב גודלין:"},{"n":"ג","t":"(ג) שנפסק כולו - ר\"ל שבשני ראשיו לא נשתייר כדי עניבה פסול אף ששאר החוטין היו שלמים ואם נשתייר בשניהם כדי עניבה ע\"י צירוף יש להסתפק אם מהני ומשמע מא\"ר וכן מדה\"ח דיש להחמיר בדבר ואפילו אם יש ספק אם השני ראשין הם משני חוטין או מאחד וא\"כ יש כאן ס\"ס שמא הם משני חוטין ושמא מצטרפין אפ\"ה יש להחמיר משום דציצית מצויין הן והארה\"ח מיקל בכגון זה ונראה דאם יש באחד מהראשין כדי לענוב חוט אחד בודאי יש לסמוך עליו:"},{"n":"ד","t":"(ד) פסול - עיין לקמן בס\"ג ולכו\"ע אם נפסק חוט אחד מעיקרו דהיינו במקום חיבורו בכנף דפסול וכתב הט\"ז ע\"כ ראוי לכל י\"ש שיעיין בשעת בדיקה גם בתחלת מוצאם של הציצית דהיינו במקום חיבורו בכנף אם יש שם קרע:"},{"n":"ה","t":"(ה) שני ראשים - ולא נשתייר בשום אחד מהן כדי עניבה אבל אם באחד מהן יש כדי עניבה כשר:"},{"n":"ו","t":"(ו) שמא נפסק וכו' - ר\"ל אף אם שני הנפסקים מצד אחד מ\"מ פן שניהם הם מחוט אחד כיון שלא דקדק בעת עשייה:"},{"n":"ז","t":"(ז) ב' ראשים וכו' - ה\"ה אפילו כל הראשים נפסקו מצד אחד ומהארבעה ראשים שמצד השני לא נשתייר בכל אחד רק כדי עניבה ג\"כ כשר דלא נפסל לדעה זו רק אם חסר חוט אחד בשני ראשיו ומ\"ש המחבר שהרי יש בראש השני יותר מכדי עניבה לאו דוקא הוא. שאלה חוטי הציצית שנפסקו וחזר וקשרן אם מועיל מה שנעשו שלמים ע\"י קשירה ומסקי האחרונים דדינא הכי אם מתחלה קודם שעשה הציצית מהחוטין נפסקו החוטין וקשרן בקשר קיימא ואח\"כ עשה מהן ציצית כשר דקשירה הוי חיבור גמור וכן לאחר שנעשה בהכשר דהיינו אם נפסק ראש אחד לאחר הטלת הציצית בהבגד אף אם לא נשתייר בו כדי עניבה מהני לקשרו עתה ואף אם יפסק אח\"כ ראש השני מאותו החוט יהיה כשר כיון שבעת הקשירה היה הציצית כשר אבל אם נתקצרו החוטין באופן שנפסלו הציצית עי\"ז כגון שנפסקו שני ראשין ולא נשתיירו כדי עניבה או שנפסק החוט במקום הנקב לא מהני מה שחזר אח\"כ וקשר דזהו בכלל תעשה ולא מן העשוי בפסול וכ\"ש אם היה החוט קצר משיעורו בתחלתו בשעת עשייה בודאי לא מהני מה שחזר אח\"כ וקשרו לאחר הכריכה והקשירה של חוליא ראשונה דזהו ממש תעשה ולא מן העשוי וכדלעיל בסימן י\"א סעיף י\"ג לענין חתך ראשי החוטין:"},{"n":"ח","t":"(ח) ולר\"ת וכו' - טעמו דשני חוטין שהן ד' אנו נותנין במקום תכלת ושני חוטין שהן ד' אנו נותנין במקום לבן צריך עכ\"פ שיהיה מין א' שלם:"}]}]}};
